        renderCustom: (container) => {
            const s = envState;
            const dirAngle = (Math.atan2(s.windDirection[0], s.windDirection[2]) * 180) / Math.PI;
            const dirAngleNorm = (dirAngle + 360) % 360;
            cardContainer(container, (c) => {
                addSliderRow(
                    c,
                    '风向角度',
                    dirAngleNorm,
                    0,
                    360,
                    1,
                    (v) => {
