                    undefined,
                    {
                        bind: () => envState.particleEmitRate,
                    }
                );
                addSliderRow(
                    c,
                    '大小',
                    s.particleSize,
                    0.1,
                    3,
                    0.1,
                    (v) => {
                        setEnvState({ particleSize: v });
                    },
                    'lucide:maximize',
                    undefined,
                    {
                        bind: () => envState.particleSize,
                    }
                );
                addSliderRow(
                    c,
                    '速度',
                    s.particleSpeed,
                    0.1,
                    5,
                    0.1,
                    (v) => {
                        setEnvState({ particleSpeed: v });
                    },
                    'lucide:gauge',
                    undefined,
                    {
                        bind: () => envState.particleSpeed,
                    }
                );
                addToggleRow(
                    c,
                    '落地溅射',
                    s.particleSplash,
                    (v) => {
                        setEnvState({ particleSplash: v });
                    },
                    'lucide:splash',
                    {
                        bind: () => envState.particleSplash,
                    }
                );
                // 自定义纹理按钮
                const texRow = document.createElement('div');
                texRow.className = 'cs-row';
                const texLabel = document.createElement('span');
                texLabel.textContent = '自定义纹理';
                texRow.appendChild(texLabel);
                const texBtn = document.createElement('button');
                texBtn.className = 'cs-btn cs-btn-sm';
                texBtn.textContent = envState.particleCustomTexture ? '更换' : '选择';
                const ensureClearBtn = (): HTMLButtonElement => {
                    const existing = texRow.querySelector<HTMLButtonElement>(
                        'button.cs-btn[data-clear]'
                    );
                    if (existing) {
                        return existing;
                    }
                    const btn = document.createElement('button');
                    btn.className = 'cs-btn cs-btn-sm';
                    btn.dataset.clear = '1';
                    btn.textContent = '清除';
                    btn.onclick = () => {
                        setEnvState({ particleCustomTexture: '' });
                        texBtn.textContent = '选择';
                        btn.remove();
                    };
                    texRow.appendChild(btn);
                    return btn;
                };
                texBtn.onclick = () => {
                    const input = document.createElement('input');
                    input.type = 'file';
                    input.accept = 'image/*';
                    input.onchange = () => {
                        const file = input.files?.[0];
                        if (!file) {
                            return;
                        }
                        const reader = new FileReader();
                        reader.onload = (e) => {
                            const url = (e.target?.result as string) ?? '';
                            setEnvState({ particleCustomTexture: url });
                            texBtn.textContent = '更换';
                            ensureClearBtn();
                        };
                        reader.readAsDataURL(file);
                    };
                    input.click();
                };
                texRow.appendChild(texBtn);
                if (envState.particleCustomTexture) {
                    ensureClearBtn();
                }
                c.appendChild(texRow);
            });
        },
    };
}

// ======== Env Stack onFolderEnter ========

function envOnFolderEnter(row: PopupRow): PopupLevel | null {
    switch (row.target) {
        case 'env:sky':
            return buildEnvUnifiedLevel();
        case 'env:lighting':
            return buildEnvLightingLevel();
        case 'env:ground':
            return buildGroundLevel();
        case 'env:water':
            return buildWaterLevel();
        case 'env:particle':
            return buildParticleLevel();
        case 'env:wind':
            return buildWindLevel();
        case 'env:cloud':
            return buildCloudLevel();
        case 'env:fog':
            return buildFogLevel();
        case 'env:shadow':
            return buildShadowLevel();
        case 'env:experimental':
            return buildExperimentalLevel();
        case 'env:presets':
            return buildPresetLevel();
        default:
            return null;
    }
}

