    applyEnvPresetObject,
    transitionRenderState,
    defaultRenderState,
} from '../scene/scene';
import { getLightState, transitionLighting } from '../scene/render/lighting';
import {
    TIME_OF_DAY_PRESETS,
    exportEnvPreset,
    importEnvPreset,
    type EnvPreset,
} from '../scene/env/env-lighting';
import {
    SaveEnvPreset,
    LoadEnvPreset,
    ListEnvPresets,
    DeleteEnvPreset,
} from '../core/wails-bindings';

