import { PopupLevel, PopupRow, showHint, hideHint } from '../core/config';
import { createIconifyIcon } from '../core/icons';
import { slideRow, addSliderRow, addToggleRow, addModeSlider } from '../core/ui-helpers';
import { subscribe } from '../core/reactivity';

/** 菜单过渡时间常量（与 app.css :root --menu-transition-duration 同步） */
const TRANSITION_DURATION = '0.15s';
const TRANSITION_DURATION_FAST = '0.12s';

/** 渲染上下文栈 — 控件创建函数通过 getCurrentRenderingMenu() 获得当前菜单 */
const _renderingStack: SlideMenu[] = [];

/** 获取当前正在渲染的 SlideMenu 实例（供 ui-helpers 中的控件函数自动注册） */
export function getCurrentRenderingMenu(): SlideMenu | null {
    return _renderingStack[_renderingStack.length - 1] ?? null;
}

export class SlideMenu {
    private levels: PopupLevel[] = [];
    private container: HTMLElement;
    private viewport: HTMLElement;
    private panel: HTMLElement;
    private headerEl: HTMLElement;
    private focusIndex = -1;
    private transitioning = false;
    /** 跟踪未决的 setTimeout，确保 cancelAnims 能全部清除 */
    private _pendingTimeouts: ReturnType<typeof setTimeout>[] = [];
    /** 缓存的额外按钮，避免每次 updateHeader 重建、旧监听器泄漏 */
    private _cachedExtraBtns: HTMLElement[] | null = null;
    /** 记录未决的 RAF reRender，用于去抖 */
    private _reRenderPending = false;
    /** keydown 监听器引用，供 dispose 清理 */
    private _keydownHandler: ((e: KeyboardEvent) => void) | null = null;
    /** 触屏滑动手势起始坐标 */
    private _swipeStartX = 0;
    private _swipeStartY = 0;
    private _swipeTouchStartHandler: ((e: TouchEvent) => void) | null = null;
    private _swipeTouchEndHandler: ((e: TouchEvent) => void) | null = null;
    /** 自更新控件注册表 — 每个元素有 update() 方法，由 updateControls() 统一调用 */
    private _controls: Array<{ update: () => void }> = [];
    /** 响应式订阅取消函数 — dispose 时调用 */
    private _unsubscribe: (() => void) | null = null;

    onItemClick?: (row: PopupRow, menu: SlideMenu) => void;
    onFolderEnter?: (row: PopupRow, menu: SlideMenu) => PopupLevel | null;
    onHover?: (row: PopupRow, entering: boolean) => void;
    onAfterRender?: (level: PopupLevel, menu: SlideMenu) => void;
    onClose?: () => void;
    extraButtonFactory?: () => HTMLElement[];

    constructor(opts: {
        container: HTMLElement;
        onItemClick?: (row: PopupRow, menu: SlideMenu) => void;
        onFolderEnter?: (row: PopupRow, menu: SlideMenu) => PopupLevel | null;
        onHover?: (row: PopupRow, entering: boolean) => void;
        onAfterRender?: (level: PopupLevel, menu: SlideMenu) => void;
        onClose?: () => void;
        extraButtonFactory?: () => HTMLElement[];
    }) {
        this.container = opts.container;
        this.onItemClick = opts.onItemClick;
        this.onFolderEnter = opts.onFolderEnter;
        this.onHover = opts.onHover;
        this.onAfterRender = opts.onAfterRender;
        this.onClose = opts.onClose;
        this.extraButtonFactory = opts.extraButtonFactory;

        this.container.innerHTML = '';
        this.container.classList.add('slide-menu');

        this.viewport = document.createElement('div');
        this.viewport.className = 'slide-viewport';

        this.panel = document.createElement('div');
        this.panel.className = 'slide-panel';
        // 内联样式由 CSS 控制，只设置必要的过渡
        this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        this.panel.style.display = 'flex';

        this.viewport.appendChild(this.panel);
        this.container.appendChild(this.viewport);

        this.headerEl = document.createElement('div');
        this.headerEl.className = 'slide-header';
        this.container.appendChild(this.headerEl);

        // 键盘导航
        this.container.tabIndex = -1;
        this._keydownHandler = (e) => {
            if (this.transitioning) {
                return;
            }
            switch (e.key) {
                case 'ArrowDown':
                    e.preventDefault();
                    this.focusNext();
                    break;
                case 'ArrowUp':
                    e.preventDefault();
                    this.focusPrev();
                    break;
                case 'ArrowRight':
                case 'Enter':
                    e.preventDefault();
                    this.activateFocused();
                    break;
                case 'ArrowLeft':
                    e.preventDefault();
                    this.pop();
                    break;
            }
        };
        this.container.addEventListener('keydown', this._keydownHandler);

        // 触屏手势：右滑返回上一层级
        this._swipeStartX = 0;
        this._swipeStartY = 0;
        this._swipeTouchStartHandler = (e: TouchEvent) => {
            if (e.touches.length === 1) {
                this._swipeStartX = e.touches[0].clientX;
                this._swipeStartY = e.touches[0].clientY;
            }
        };
        this._swipeTouchEndHandler = (e: TouchEvent) => {
            if (this.transitioning || this.levels.length <= 1) {
                return;
            }
            const ct = e.changedTouches[0];
            if (!ct) {
                return;
            }
            const dx = ct.clientX - this._swipeStartX;
            const dy = Math.abs(ct.clientY - this._swipeStartY);
            // 右滑 > 60px 且垂直偏移 < 40px → 返回
            if (dx > 60 && dy < 40) {
                this.pop();
            }
        };
        this.container.addEventListener('touchstart', this._swipeTouchStartHandler, {
            passive: true,
        });
        this.container.addEventListener('touchend', this._swipeTouchEndHandler, { passive: true });

        // 响应式订阅：状态变更 → 自动 updateControls
        this._unsubscribe = subscribe(() => this.updateControls());
    }

    // ======== 公共 API ========

    get currentLevel(): PopupLevel | undefined {
        return this.levels[this.levels.length - 1];
    }

    get levelCount(): number {
        return this.levels.length;
    }

    reset(level: PopupLevel): void {
        this._cancelAnim();
        this.levels = [level];
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        this.buildPanel(level).then(() => {
            this.updateHeader(level);
            this.setupFocus();
            this.onAfterRender?.(level, this);
        });
    }

    push(level: PopupLevel): void {
        if (this.transitioning) {
            return;
        }
        this.transitioning = true;
        this.levels.push(level);

        // 旧内容淡出
        this.panel.style.transition = `opacity ${TRANSITION_DURATION_FAST} ease, transform ${TRANSITION_DURATION_FAST} ease`;
        this.panel.style.opacity = '0';
        this.panel.style.transform = 'translateX(-8px)';

        const onFadeOut = async () => {
            this.panel.removeEventListener('transitionend', onFadeOut);
            await this.buildPanel(level);
            this.updateHeader(level);
            // 新内容从下方淡入
            this.panel.style.transition = 'none';
            this.panel.style.opacity = '0';
            this.panel.style.transform = 'translateX(8px)';
            void this.panel.offsetHeight;
            this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
            this.panel.style.opacity = '1';
            this.panel.style.transform = 'translateX(0)';

            const onFadeIn = () => {
                this.panel.removeEventListener('transitionend', onFadeIn);
                this._cancelTimeout();
                this.transitioning = false;
                this.setupFocus();
                this.onAfterRender?.(level, this);
            };
            this.panel.addEventListener('transitionend', onFadeIn);
            this._pushTimeout(
                setTimeout(() => {
                    if (this.transitioning) {
                        this.panel.style.opacity = '1';
                        this.panel.style.transform = 'translateX(0)';
                        this.transitioning = false;
                        this.setupFocus();
                        this.onAfterRender?.(level, this);
                    }
                }, 200)
            );
        };

        this.panel.addEventListener('transitionend', onFadeOut);
        this._pushTimeout(
            setTimeout(() => {
                if (this.transitioning) {
                    this.panel.style.opacity = '0';
                    this.panel.style.transform = 'translateX(-8px)';
                    onFadeOut();
                }
            }, 150)
        );
    }

    pop(): void {
        if (this.transitioning || this.levels.length <= 1) {
            return;
        }
        this.transitioning = true;
        this.levels.pop();
        const prevLevel = this.levels[this.levels.length - 1];

        this.panel.style.transition = `opacity ${TRANSITION_DURATION_FAST} ease, transform ${TRANSITION_DURATION_FAST} ease`;
        this.panel.style.opacity = '0';
        this.panel.style.transform = 'translateX(8px)';

        const onFadeOut = async () => {
            this.panel.removeEventListener('transitionend', onFadeOut);
            await this.buildPanel(prevLevel);
            this.updateHeader(prevLevel);
            this.panel.style.transition = 'none';
            this.panel.style.opacity = '0';
            this.panel.style.transform = 'translateX(-8px)';
            void this.panel.offsetHeight;
            this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
            this.panel.style.opacity = '1';
            this.panel.style.transform = 'translateX(0)';

            const onFadeIn = () => {
                this.panel.removeEventListener('transitionend', onFadeIn);
                this._cancelTimeout();
                this.transitioning = false;
                this.setupFocus();
                this.onAfterRender?.(prevLevel, this);
            };
            this.panel.addEventListener('transitionend', onFadeIn);
            this._pushTimeout(
                setTimeout(() => {
                    if (this.transitioning) {
                        this.panel.style.opacity = '1';
                        this.panel.style.transform = 'translateX(0)';
                        this.transitioning = false;
                        this.setupFocus();
                        this.onAfterRender?.(prevLevel, this);
                    }
                }, 200)
            );
        };

        this.panel.addEventListener('transitionend', onFadeOut);
        this._pushTimeout(
            setTimeout(() => {
                if (this.transitioning) {
                    this.panel.style.opacity = '0';
                    this.panel.style.transform = 'translateX(8px)';
                    onFadeOut();
                }
            }, 150)
        );
    }

    popTo(index: number): void {
        if (index < 0 || index >= this.levels.length || this.transitioning) {
            return;
        }
        if (index === this.levels.length - 1) {
            return;
        }
        this._cancelAnim();
        this.levels = this.levels.slice(0, index + 1);
        const level = this.currentLevel!;
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        this.buildPanel(level).then(() => {
            this.updateHeader(level);
            this.setupFocus();
            this.onAfterRender?.(level, this);
        });
    }

    reRender(opts?: { preserveFocus?: boolean }): void {
        if (this.transitioning) {
            return;
        }
        // RAF 去抖：同帧内多次 reRender 合并为一次
        if (this._reRenderPending) {
            return;
        }
        this._reRenderPending = true;
        requestAnimationFrame(() => {
            this._reRenderPending = false;
            this._doReRender(opts);
        });
    }

    /** 注册一个自更新控件，由 updateControls() 统一驱动刷新 */
    registerControl(update: () => void): void {
        this._controls.push({ update });
    }

    /** 增量刷新所有已注册的自更新控件（不重建 DOM） */
    updateControls(): void {
        for (const c of this._controls) {
            c.update();
        }
    }

    private _doReRender(opts?: { preserveFocus?: boolean }): void {
        const level = this.currentLevel;
        if (!level) {
            return;
        }
        this._cachedExtraBtns = null;

        const finalize = () => {
            this.updateHeader(level);
            // reRenderCustom 路径是增量更新，不抢焦点
            const preserve = opts?.preserveFocus ?? level.reRenderCustom !== undefined;
            if (!preserve) {
                this.setupFocus();
            }
            this.onAfterRender?.(level, this);
        };

        if (level.reRenderCustom) {
            // === 增量路径：patch items（非空时）+ reRenderCustom ===
            const list = this.panel.querySelector('.slide-list');
            if (list) {
                if (level.items.length > 0) {
                    this.patchPanel(level.items);
                }
                level.reRenderCustom(list as HTMLElement);
                finalize();
                return;
            }
            // 没有旧 DOM → 退化为全量重建
            this.buildPanel(level).then(finalize);
        } else if (level.renderCustom || level.items.length === 0) {
            // === 自定义渲染 / 空列表 → 全量重建 ===
            this.buildPanel(level).then(finalize);
        } else {
            // === 纯 items → 全量重建（card-per-divider 结构不支持增量 patch） ===
            this.buildPanel(level).then(finalize);
            finalize();
        }
    }

    /** 重置导航栈到根层级，不触发渲染 */
    resetToRoot(): void {
        if (this.levels.length > 1) {
            this.levels = [this.levels[0]];
        }
    }

    getLevel(index: number): PopupLevel | undefined {
        return this.levels[index];
    }

    setLevel(index: number, level: PopupLevel): void {
        if (index >= 0 && index < this.levels.length) {
            this.levels[index] = level;
            // 如果替换的是当前显示层级，自动重绘
            if (index === this.levels.length - 1) {
                this.reRender();
            }
        }
    }

    /**
     * 精准替换第 index 行的 DOM，不走 reRender 全量重建。
     * 常用于单行状态变化（开关、选中态等）。
     */
    updateRow(index: number, row: PopupRow): void {
        const level = this.currentLevel;
        if (!level || index < 0 || index >= level.items.length) {
            return;
        }
        level.items[index] = row;
        const list = this.panel.querySelector('.slide-list');
        if (!list) {
            return;
        }
        const oldChild = list.children[index] as HTMLElement | undefined;
        if (oldChild) {
            const newEl = this.createRow(row);
            if (newEl) {
                oldChild.replaceWith(newEl);
            }
        }
    }

    /** 只刷新标题栏（返回按钮 + 标题 + 额外按钮），不碰面板 */
    refreshHeader(): void {
        const level = this.currentLevel;
        if (!level) {
            return;
        }
        this._cachedExtraBtns = null;
        this.updateHeader(level);
    }

    /** 强制结束当前动画，清除所有未决定时器，重置过渡状态 */
    private _cancelAnim(): void {
        this.transitioning = false;
        this._reRenderPending = false;
        this._cancelTimeout();
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
    }

    /** 记录一个由动画生命周期管理的 setTimeout */
    private _pushTimeout(id: ReturnType<typeof setTimeout>): void {
        this._pendingTimeouts.push(id);
    }

    /** 清除所有未决的动画后备 setTimeout */
    private _cancelTimeout(): void {
        for (const id of this._pendingTimeouts) {
            clearTimeout(id);
        }
        this._pendingTimeouts = [];
    }

    // ======== 内部方法 ========

    private get panelItems(): NodeListOf<HTMLElement> {
        return this.panel.querySelectorAll<HTMLElement>('.slide-item');
    }

    private clearFocus(): void {
        this.panel
            .querySelectorAll('.slide-focused')
            .forEach((el) => el.classList.remove('slide-focused'));
    }

    private applyFocus(): void {
        this.clearFocus();
        const items = this.panelItems;
        if (this.focusIndex < 0 || this.focusIndex >= items.length) {
            return;
        }
        items[this.focusIndex].classList.add('slide-focused');
        items[this.focusIndex].scrollIntoView({ block: 'nearest' });
    }

    private setupFocus(): void {
        this.focusIndex = -1;
        this.clearFocus();
        if (this.panelItems.length > 0) {
            this.focusIndex = 0;
            this.applyFocus();
        }
        this.container.focus({ preventScroll: true });
    }

    private focusPrev(): void {
        const len = this.panelItems.length;
        if (len === 0) {
            return;
        }
        this.focusIndex = this.focusIndex <= 0 ? len - 1 : this.focusIndex - 1;
        this.applyFocus();
    }

    private focusNext(): void {
        const len = this.panelItems.length;
        if (len === 0) {
            return;
        }
        this.focusIndex = this.focusIndex >= len - 1 ? 0 : this.focusIndex + 1;
        this.applyFocus();
    }

    private activateFocused(): void {
        const items = this.panelItems;
        if (this.focusIndex < 0 || this.focusIndex >= items.length) {
            return;
        }
        items[this.focusIndex].click();
    }

    private _buildSeq = 0;

    // ======== 增量渲染 ========

    /** 生成行的稳定标识 key：优先用 row.rowKey，否则按 kind:target 自动推导 */
    private rowKey(row: PopupRow): string {
        if (row.rowKey) {
            return row.rowKey;
        }
        if (row.kind === 'divider') {
            return '__divider__';
        }
        return `${row.kind}:${row.target}`;
    }

    /** 增量 patch 当前 panel：只创建/替换/删除有变化的行 */
    private patchPanel(items: PopupRow[]): void {
        if (items.length === 0) {
            return;
        }
        const list = this.panel.querySelector('.slide-list');
        if (!list) {
            this.buildPanel(this.currentLevel!);
            return;
        }

        // 如果有 lcard 包裹，在 lcard 内部 patch
        const card = list.querySelector('.lcard') as HTMLElement | null;
        const container = card || list;
        const oldChildren = Array.from(container.children) as HTMLElement[];
        const maxLen = Math.max(oldChildren.length, items.length);

        // 1. 删除多余的行（从后往前，避免索引偏移）
        for (let i = oldChildren.length - 1; i >= items.length; i--) {
            oldChildren[i].remove();
        }

        // 2. 逐行比较
        for (let i = 0; i < items.length; i++) {
            const newRow = items[i];
            const newKey = this.rowKey(newRow);

            if (i < oldChildren.length) {
                const oldEl = oldChildren[i];
                const oldKey = oldEl.dataset.rowKey || '';
                if (oldKey !== newKey) {
                    // key 不匹配 → 替换整行
                    const newEl = this.createRow(newRow);
                    if (newEl) {
                        oldEl.replaceWith(newEl);
                    }
                }
                // key 匹配 → 行不变，跳过 DOM 操作
            } else {
                // 追加新行
                const newEl = this.createRow(newRow);
                if (newEl) {
                    container.appendChild(newEl);
                }
            }
        }
    }

    private async buildPanel(level: PopupLevel): Promise<void> {
        const seq = ++this._buildSeq;
        this.panel.innerHTML = '';
        // 每次重建面板，清空旧的控件注册表
        this._controls = [];
        const list = document.createElement('div');
        list.className = 'slide-list';

        if (level.items.length === 0 && !level.renderCustom) {
            list.innerHTML = '<div class="slide-empty">暂无内容</div>';
        } else if (level.items.length > 0 && !level.renderCustom) {
            // 纯 items 菜单：按 divider 分组，每组包一个 lcard
            let card: HTMLElement | null = null;
            for (const row of level.items) {
                if (row.kind === 'divider') {
                    card = null; // 关闭当前组，下一个非 divider 行开启新组
                    continue;
                }
                if (!card) {
                    card = document.createElement('div');
                    card.className = 'lcard';
                    list.appendChild(card);
                }
                const el = this.createRow(row);
                if (el) {
                    card.appendChild(el);
                }
            }
        } else {
            // 有 renderCustom：先渲染 items 导航行，再调自定义回调
            for (const row of level.items) {
                const el = this.createRow(row);
                if (el) {
                    list.appendChild(el);
                }
            }
            _renderingStack.push(this);
            try {
                await level.renderCustom(list);
            } finally {
                _renderingStack.pop();
            }
        }
        // 只有最新的 build 才 appendChild，防止并发导致重复
        if (seq === this._buildSeq) {
            this.panel.appendChild(list);
        }
    }

    /** 释放所有资源（清除动画定时器、键盘/触摸监听、状态），调用后实例不可再用。 */
    dispose(): void {
        this._cancelAnim();
        if (this._unsubscribe) {
            this._unsubscribe();
            this._unsubscribe = null;
        }
        if (this._keydownHandler) {
            this.container.removeEventListener('keydown', this._keydownHandler);
            this._keydownHandler = null;
        }
        if (this._swipeTouchStartHandler) {
            this.container.removeEventListener('touchstart', this._swipeTouchStartHandler);
            this._swipeTouchStartHandler = null;
        }
        if (this._swipeTouchEndHandler) {
            this.container.removeEventListener('touchend', this._swipeTouchEndHandler);
            this._swipeTouchEndHandler = null;
        }
        this.levels = [];
        this._cachedExtraBtns = null;
    }

    private updateHeader(level: PopupLevel): void {
        this.headerEl.innerHTML = '';
        const backBtn = document.createElement('span');
        backBtn.className = 'slide-back';
        const backIcon = createIconifyIcon(
            this.levels.length > 1 ? 'lucide:chevron-left' : 'lucide:x'
        );
        if (backIcon) {
            backBtn.appendChild(backIcon);
        }
        if (this.levels.length > 1) {
            backBtn.addEventListener('click', () => this.pop());
        } else {
            backBtn.addEventListener('click', () => this.onClose());
        }
        this.headerEl.appendChild(backBtn);

        const title = document.createElement('span');
        title.className = 'slide-title';
        title.textContent = level.label || '';
        this.headerEl.appendChild(title);

        // 复用额外按钮，避免每次重建创建新 DOM + 旧监听器泄漏
        if (!this._cachedExtraBtns) {
            this._cachedExtraBtns = this.extraButtonFactory?.() ?? [];
        }
        for (const btn of this._cachedExtraBtns) {
            this.headerEl.appendChild(btn);
        }
    }

    private createRow(row: PopupRow): HTMLElement | null {
        if (row.kind === 'divider') {
            const el = document.createElement('div');
            el.className = 'slide-divider';
            return el;
        }

        // ======== 新 kind：slider / toggle / modeSlider / chips ========
        // 这些 kind 不是可点击的导航行，而是内嵌控件行。
        // 通过 ui-helpers 渲染，包一层带 rowKey 的 wrapper 以支持增量 patch。
        if (
            row.kind === 'slider' ||
            row.kind === 'toggle' ||
            row.kind === 'modeSlider' ||
            row.kind === 'chips'
        ) {
            const wrapper = document.createElement('div');
            wrapper.dataset.rowKey = this.rowKey(row);
            if (row.kind === 'slider') {
                addSliderRow(
                    wrapper,
                    row.label,
                    row.sliderValue ?? 0,
                    row.sliderMin ?? 0,
                    row.sliderMax ?? 1,
                    row.sliderStep ?? 0.1,
                    row.onSliderChange ?? (() => {}),
                    row.icon || undefined,
                    row.onSliderDragEnd
                );
            } else if (row.kind === 'toggle') {
                addToggleRow(
                    wrapper,
                    row.label,
                    row.toggleValue ?? false,
                    row.onToggleChange ?? (() => {}),
                    row.icon || undefined
                );
            } else if (row.kind === 'modeSlider') {
                addModeSlider(
                    wrapper,
                    row.label,
                    row.modeOptions ?? [],
                    row.modeValue as string & (string | number),
                    row.onModeChange ?? (() => {}),
                    row.icon || undefined
                );
            } else if (row.kind === 'chips') {
                wrapper.className = 'preset-group';
                for (const chip of row.chips ?? []) {
                    const btn = document.createElement('button');
                    btn.textContent = chip.label;
                    btn.className = 'preset-chip' + (chip.active ? ' active' : '');
                    btn.addEventListener('click', chip.onClick);
                    wrapper.appendChild(btn);
                }
            }
            return wrapper;
        }

        // ======== folder / model / action：原有 slide-item 逻辑 ========

        // folder + headerToggle：委托给 slideRow（与 renderCustom 中的视觉一致）
        if (row.kind === 'folder' && row.headerToggle) {
            const wrapper = document.createElement('div');
            slideRow(
                wrapper,
                row.icon,
                row.label,
                true,
                () => {
                    const next = this.onFolderEnter(row, this);
                    if (next) {
                        this.push(next);
                    }
                },
                row.sublabel,
                row.catTag,
                undefined,
                row.headerToggle
            );
            const el = wrapper.firstChild as HTMLElement | null;
            if (el) {
                el.dataset.rowKey = this.rowKey(row);
                const hint = row.sublabel || '暂无提示';
                el.setAttribute('data-hint', hint);
                el.addEventListener('mouseenter', () => {
                    if (this.focusIndex >= 0) {
                        this.clearFocus();
                        this.focusIndex = -1;
                    }
                    showHint(hint);
                    this.onHover?.(row, true);
                });
                el.addEventListener('mouseleave', () => {
                    hideHint();
                    this.onHover?.(row, false);
                });
            }
            return el;
        }

        const el = document.createElement('div');
        el.className = 'slide-item';
        el.dataset.rowKey = this.rowKey(row);
        const hint = row.sublabel || (row.model ? '暂无描述' : '暂无提示');
        el.setAttribute('data-hint', hint);

        const iconSpan = document.createElement('span');
        iconSpan.className = 'slide-icon';
        const iconEl = createIconifyIcon(row.icon);
        if (iconEl) {
            iconSpan.appendChild(iconEl);
        } else {
            iconSpan.textContent = row.icon;
        }
        el.appendChild(iconSpan);

        const labelSpan = document.createElement('span');
        labelSpan.className = 'slide-label';
        labelSpan.textContent = row.label;
        el.appendChild(labelSpan);

        if (row.catTag) {
            const tagSpan = document.createElement('span');
            tagSpan.className = 'slide-tag';
            tagSpan.textContent = row.catTag;
            el.appendChild(tagSpan);
        }

        if (row.kind === 'folder') {
            const arrow = document.createElement('span');
            arrow.className = 'slide-arrow';
            arrow.textContent = '>';
            el.appendChild(arrow);
        }

        if (row.onAddClick) {
            const addBtn = document.createElement('span');
            addBtn.className = 'slide-add-btn';
            addBtn.textContent = '+';
            addBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                row.onAddClick!();
            });
            el.appendChild(addBtn);
        }

        if (row.kind === 'folder') {
            el.addEventListener('click', (e) => {
                if ((e.target as HTMLElement).closest('.slide-add-btn')) {
                    return;
                }
                const next = this.onFolderEnter(row, this);
                if (next) {
                    this.push(next);
                }
            });
        } else {
            el.addEventListener('click', () => this.onItemClick(row, this));
        }

        el.addEventListener('mouseenter', () => {
            if (this.focusIndex >= 0) {
                this.clearFocus();
                this.focusIndex = -1;
            }
            showHint(hint);
            this.onHover?.(row, true);
        });
        el.addEventListener('mouseleave', () => {
            hideHint();
            this.onHover?.(row, false);
        });

        return el;
    }
}

// [doc:architecture] Model Material — 材质调节 UI 层（batch/per-mat/root/list）

import { Material } from '@babylonjs/core/Materials/material';
import { StandardMaterial } from '@babylonjs/core/Materials/standardMaterial';
import { cardContainer, setStatus, PopupLevel, stackRegistry, escapeHtml } from '../core/config';
import {
    getMatCatGroups,
    getMatCatParams,
    setMatCatParams,
    resetMatCatParams,
    getMatDetailList,
    getMatParams,
    setMatParams,
    resetSingleMatParams,
    resetAllMatParams,
    isMatEnabled,
    setMatEnabled,
    isMatCategoryAllEnabled,
    setMatCategoryEnabled,
    getMaterialMeshes,
} from '../scene/scene';
import { createIconifyIcon } from '../core/icons';
import { slideRow, addSliderRow, addCollapsible } from '../core/ui-helpers';
import type { SlideMenu } from './menu';

let _selectedMat: { cat: string; index: number } | null = null;
/** 参数卡片容器引用（增量更新用，避免 reRender） */
let _paramCardEl: HTMLElement | null = null;

export function buildMatBatchLevel(id: string, modelName: string): PopupLevel {
    const label = '按部位批量 — ' + modelName;
    return {
        label,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const groups = getMatCatGroups(id);
            const detailList = getMatDetailList(id);
            const overrideCount = detailList.filter((d) => d.modified).length;

            cardContainer(container, (c) => {
                if (overrideCount > 0) {
                    const hint = document.createElement('div');
                    hint.style.cssText =
                        'font-size:11px;color:var(--warn);margin-bottom:8px;padding:4px 10px;background:var(--white-04);border-radius:6px;text-align:center;';
                    hint.textContent = `⚠ ${overrideCount} 个材质有单独覆盖（分类调整不影响已覆盖材质）`;
                    c.appendChild(hint);
                }

                const CATEGORY_ICONS: Record<string, string> = {
                    皮肤: 'droplet',
                    头发: 'feather',
                    眼睛: 'eye',
                    服装: 'shirt',
                };

                for (const [cat, mats] of groups) {
                    const params = getMatCatParams(id, cat);
                    addCollapsible(c, {
                        title: `${cat} (${mats.length})`,
                        icon: CATEGORY_ICONS[cat] || 'box',
                        defaultOpen: false,
                        headerToggle: {
                            value: isMatCategoryAllEnabled(id, cat),
                            onChange: (v) => setMatCategoryEnabled(id, cat, v),
                            bind: () => isMatCategoryAllEnabled(id, cat),
                        },
                        renderContent: (panel) => {
                            addSliderRow(panel, '漫反射倍率', params.diffuseMul, 0, 2, 0.05, (v) =>
                                setMatCatParams(id, cat, { diffuseMul: v })
                            );
                            addSliderRow(panel, '高光倍率', params.specularMul, 0, 2, 0.05, (v) =>
                                setMatCatParams(id, cat, { specularMul: v })
                            );
                            addSliderRow(panel, '高光指数', params.shininess, 0, 200, 1, (v) =>
                                setMatCatParams(id, cat, { shininess: v })
                            );
                            addSliderRow(panel, '环境光倍率', params.ambientMul, 0, 2, 0.05, (v) =>
                                setMatCatParams(id, cat, { ambientMul: v })
                            );
                        },
                    });
                }
            });
        },
    };
}

export function buildPerMatLevel(
    id: string,
    modelName: string,
    matName: string,
    mat: Material,
    matIndex: number,
    targetStack?: SlideMenu | null
): PopupLevel {
    const shortName = matName.length > 24 ? matName.slice(0, 24) + '…' : matName;
    return {
        label: shortName,
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                const nameEl = document.createElement('div');
                nameEl.style.cssText =
                    'font-size:11px;color:var(--text-dim);margin-bottom:8px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
                nameEl.textContent = modelName + ' > ' + matName;
                c.appendChild(nameEl);

                const stackingHint = document.createElement('div');
                stackingHint.style.cssText =
                    'font-size:10px;color:var(--text-muted);margin-bottom:10px;padding:4px 8px;background:var(--accent-dim);border-radius:4px;';
                stackingHint.textContent = '覆盖分类设置，分类调整仍生效于其他材质';
                c.appendChild(stackingHint);

                const current = getMatParams(id, matIndex);
                const params = current ?? {
                    diffuseMul: 1,
                    specularMul: 1,
                    shininess: 50,
                    ambientMul: 1,
                };
                const isModified = current !== null;

                addSliderRow(c, '漫反射倍率', params.diffuseMul, 0, 2, 0.05, (v) => {
                    setMatParams(id, matIndex, { diffuseMul: v });
                });
                addSliderRow(c, '高光倍率', params.specularMul, 0, 2, 0.05, (v) => {
                    setMatParams(id, matIndex, { specularMul: v });
                });
                addSliderRow(c, '高光指数', params.shininess, 0, 200, 1, (v) => {
                    setMatParams(id, matIndex, { shininess: v });
                });
                addSliderRow(c, '环境光倍率', params.ambientMul, 0, 2, 0.05, (v) => {
                    setMatParams(id, matIndex, { ambientMul: v });
                });

                if (isModified) {
                    slideRow(c, 'lucide:rotate-ccw', '重置此材质', false, () => {
                        resetSingleMatParams(id, matIndex);
                        (targetStack ?? stackRegistry.modelStack)?.reRender();
                        setStatus(`✓ 已重置: ${matName}`, true);
                    });
                }
            });
        },
    };
}

export function buildMatRootLevel(
    id: string,
    modelName: string,
    targetStack?: SlideMenu | null
): PopupLevel {
    _selectedMat = null;
    _paramCardEl = null;
    return {
        label: '材质调节 — ' + modelName,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const groups = getMatCatGroups(id);
            const detailList = getMatDetailList(id);

            // 卡片 1：材质组（折叠列表）
            cardContainer(container, (c) => {
                if (groups.size === 0) {
                    const empty = document.createElement('div');
                    empty.style.cssText =
                        'padding:12px 14px;text-align:center;font-size:11px;color:var(--text-dim);';
                    empty.textContent = '此模型无材质数据';
                    c.appendChild(empty);
                    return;
                }

                for (const [cat, mats] of groups) {
                    const count = mats.length;
                    addCollapsible(c, {
                        title: `${cat} (${count})`,
                        icon: 'lucide:layers',
                        defaultOpen: false,
                        headerToggle: {
                            value: isMatCategoryAllEnabled(id, cat),
                            onChange: (v) => setMatCategoryEnabled(id, cat, v),
                            bind: () => isMatCategoryAllEnabled(id, cat),
                        },
                        renderContent: (inner) => {
                            for (const matInfo of mats) {
                                const detail = detailList.find((d) => d.name === matInfo.mat.name);
                                const idx = detail ? detail.index : -1;
                                if (idx === -1) {
                                    continue;
                                }
                                const matEnabled = isMatEnabled(id, idx);
                                const mat = matInfo.mat as StandardMaterial;

                                const row = document.createElement('div');
                                row.className = `slide-item${!matEnabled ? ' mat-disabled' : ''}`;
                                row.style.cssText = 'padding-left: 28px;';
                                row.dataset.matIdx = String(idx);
                                row.dataset.matCat = cat;

                                // Label
                                const label = document.createElement('span');
                                label.className = 'slide-label';
                                label.textContent = `#${String(idx + 1).padStart(2, '0')} ${matInfo.mat.name}`;
                                row.appendChild(label);

                                if (detail.modified) {
                                    const sub = document.createElement('span');
                                    sub.className = 'slide-sublabel';
                                    sub.style.color = 'var(--accent)';
                                    sub.textContent = '已修改';
                                    row.appendChild(sub);
                                }

                                // Standard toggle 开关（替代小圆点）
                                const toggle = document.createElement('label');
                                toggle.className = 'toggle header-toggle';
                                toggle.style.marginLeft = 'auto';
                                const toggleInput = document.createElement('input');
                                toggleInput.type = 'checkbox';
                                toggleInput.checked = matEnabled;
                                const slider = document.createElement('span');
                                slider.className = 'slider';
                                toggle.appendChild(toggleInput);
                                toggle.appendChild(slider);
                                toggle.addEventListener('click', (e) => {
                                    e.stopPropagation();
                                    const newState = !isMatEnabled(id, idx);
                                    setMatEnabled(id, idx, newState);
                                    // 增量更新当前行 DOM
                                    toggleInput.checked = newState;
                                    row.classList.toggle('mat-disabled', !newState);
                                    setStatus(
                                        newState
                                            ? `✓ 已显示: ${matInfo.mat.name}`
                                            : `✕ 已隐藏: ${matInfo.mat.name}`,
                                        true
                                    );
                                });
                                row.appendChild(toggle);

                                // 行点击：只更新参数卡片，不重建列表
                                row.addEventListener('click', () => {
                                    // 更新选中高亮
                                    const prev = inner.querySelector('.slide-focused');
                                    if (prev) {
                                        prev.classList.remove('slide-focused');
                                    }
                                    row.classList.add('slide-focused');
                                    // 增量更新参数卡片
                                    _selectedMat = { cat, index: idx };
                                    _renderParamCard(
                                        id,
                                        modelName,
                                        cat,
                                        idx,
                                        detailList,
                                        targetStack
                                    );
                                });
                                inner.appendChild(row);
                            }
                        },
                    });
                }
            });

            // 卡片 2：参数微调容器（占位，内容由 _renderParamCard 增量填充）
            _paramCardEl = document.createElement('div');
            container.appendChild(_paramCardEl);
            _renderParamCard(id, modelName, null, -1, detailList, targetStack);

            // 卡片 3：重置全部
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:refresh-ccw', '重置全部材质参数', false, () => {
                    resetMatCatParams(id);
                    resetAllMatParams(id);
                    _selectedMat = null;
                    (targetStack ?? stackRegistry.modelStack)?.reRender();
                    setStatus('✓ 全部材质参数已重置', true);
                });
            });
        },
    };
}

/**
 * 增量渲染参数卡片（替代 reRender 全量重建）。
 * 只更新 _paramCardEl 容器的内容，不影响材质列表。
 */
function _renderParamCard(
    id: string,
    modelName: string,
    cat: string | null,
    index: number,
    detailList: { name: string; index: number; modified: boolean }[],
    targetStack?: SlideMenu | null
): void {
    if (!_paramCardEl) {
        return;
    }
    // 防止幽灵引用：容器被销毁后置 null
    if (!_paramCardEl.isConnected) {
        _paramCardEl = null;
        return;
    }
    _paramCardEl.innerHTML = '';

    if (index === -1 || !cat) {
        const hint = document.createElement('div');
        hint.style.cssText =
            'font-size:11px;color:var(--text-dim);padding:12px 14px;text-align:center;';
        hint.textContent = '请从上方材质列表中选择一个材质进行微调';
        _paramCardEl.appendChild(hint);
        return;
    }

    const card = document.createElement('div');
    card.className = 'card';
    card.style.cssText =
        'margin:8px;border-radius:var(--radius);background:var(--card-bg);padding:0;';

    const title = document.createElement('div');
    title.style.cssText = 'font-size:11px;color:var(--text-dim);padding:4px 14px;';
    const matName = detailList.find((d) => d.index === index)?.name || '未知材质';
    title.textContent = `参数微调 — ${cat} › ${matName}`;
    card.appendChild(title);

    const current = getMatParams(id, index);
    const params = current ?? {
        diffuseMul: 1,
        specularMul: 1,
        shininess: 50,
        ambientMul: 1,
    };

    addSliderRow(
        card,
        '漫反射倍率',
        params.diffuseMul,
        0,
        2,
        0.05,
        (v) => {
            setMatParams(id, index, { diffuseMul: v });
        },
        'lucide:droplet'
    );
    addSliderRow(
        card,
        '高光倍率',
        params.specularMul,
        0,
        2,
        0.05,
        (v) => {
            setMatParams(id, index, { specularMul: v });
        },
        'lucide:sparkle'
    );
    addSliderRow(
        card,
        '高光指数',
        params.shininess,
        0,
        200,
        1,
        (v) => {
            setMatParams(id, index, { shininess: v });
        },
        'lucide:zap'
    );
    addSliderRow(
        card,
        '环境光倍率',
        params.ambientMul,
        0,
        2,
        0.05,
        (v) => {
            setMatParams(id, index, { ambientMul: v });
        },
        'lucide:sun'
    );

    if (current !== null) {
        // 重置：批量状态变化 + 预期全量刷新，用 reRender。
        // 色块点击：单点切换，用增量更新（内联 DOM 操作），避免 200+ 行折叠列表重建。
        slideRow(card, 'lucide:rotate-ccw', '重置此材质', false, () => {
            resetSingleMatParams(id, index);
            _selectedMat = null;
            (targetStack ?? stackRegistry.modelStack)?.reRender();
            setStatus(`✓ 已重置: ${matName}`, true);
        });
    }

    _paramCardEl.appendChild(card);
}

export function buildMatListLevel(
    id: string,
    modelName: string,
    targetStack?: SlideMenu | null
): PopupLevel {
    return {
        label: '逐材质 — ' + modelName,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const detailList = getMatDetailList(id);
            cardContainer(container, (c) => {
                c.style.padding = '6px 10px';
                for (const detail of detailList) {
                    const meshes = getMaterialMeshes(id);
                    const mat = meshes?.[detail.index]?.material as StandardMaterial;
                    if (!mat) {
                        continue;
                    }

                    const matEnabled = isMatEnabled(id, detail.index);

                    const row = document.createElement('div');
                    row.className = `mat-row${detail.modified ? ' modified' : ''}${!matEnabled ? ' mat-disabled' : ''}`;

                    const idxSpan = document.createElement('span');
                    idxSpan.className = 'mat-index';
                    idxSpan.textContent = `#${String(detail.index + 1).padStart(2, '0')}`;
                    row.appendChild(idxSpan);

                    const nameSpan = document.createElement('span');
                    nameSpan.className = 'mat-name';
                    nameSpan.title = detail.name;
                    nameSpan.textContent = detail.name;
                    row.appendChild(nameSpan);

                    if (detail.modified) {
                        const modSpan = document.createElement('span');
                        modSpan.className = 'mat-modified';
                        const icon = createIconifyIcon('check-circle');
                        if (icon) {
                            modSpan.appendChild(icon);
                        }
                        row.appendChild(modSpan);
                    }

                    // Standard toggle 开关（替代小圆点）
                    const toggle = document.createElement('label');
                    toggle.className = 'toggle header-toggle';
                    toggle.style.marginLeft = 'auto';
                    const toggleInput = document.createElement('input');
                    toggleInput.type = 'checkbox';
                    toggleInput.checked = matEnabled;
                    const slider = document.createElement('span');
                    slider.className = 'slider';
                    toggle.appendChild(toggleInput);
                    toggle.appendChild(slider);
                    toggle.addEventListener('click', (e) => {
                        e.stopPropagation();
                        const newState = !isMatEnabled(id, detail.index);
                        setMatEnabled(id, detail.index, newState);
                        toggleInput.checked = newState;
                        row.classList.toggle('mat-disabled', !newState);
                        setStatus(
                            newState ? `✓ 已显示: ${detail.name}` : `✕ 已隐藏: ${detail.name}`,
                            true
                        );
                    });
                    row.appendChild(toggle);

                    row.addEventListener('click', () => {
                        (targetStack ?? stackRegistry.modelStack)?.push(
                            buildPerMatLevel(
                                id,
                                modelName,
                                detail.name,
                                mat,
                                detail.index,
                                targetStack
                            )
                        );
                    });
                    c.appendChild(row);
                }
            });
        },
    };
}

// [doc:architecture] Camera Levels — 相机参数弹窗层级
// 从 scene-menu.ts 迁移到 motion-popup.ts

import {
    setStatus,
    cardContainer,
    libraryRoot,
    stackRegistry,
    motionBindingTargetId,
    setMotionBindingTargetId,
} from '../core/config';
import type { PopupLevel } from '../core/config';
import { createIconifyIcon } from '../core/icons';
import { slideRow, addSliderRow, addToggleRow, addModeSlider } from '../core/ui-helpers';
import {
    switchCameraMode,
    getCameraMode,
    hasCameraVmd,
    clearCameraVmd,
    getOrbitParams,
    setOrbitParams,
    getFreeflyParams,
    setFreeflyParams,
    getConcertParams,
    setConcertParams,
    getConcertPaused,
    setConcertPaused,
    getFov,
    setFov,
    setAutoCameraEnabled,
    isAutoCameraEnabled,
    setAutoCameraBeatsPerSwitch,
    getAutoCameraBeatsPerSwitch,
    type CameraMode,
} from '../scene/camera/camera';
import { triggerAutoSave } from '../scene/scene';
import { getProcBeatDetector } from '../scene/scene';
import { getMotionMenu } from './motion-popup';

let cameraExpandedMode: CameraMode | null = null;

function refreshCameraLevel(): void {
    const menu = getMotionMenu();
    if (menu) {
        menu.reRender();
    }
}

export function buildCameraLevel(): PopupLevel {
    return {
        label: '相机模式',
        dir: '',
        items: [],
        renderCustom: (container) => {
            const currentMode = getCameraMode();
            const vmdLoaded = hasCameraVmd();

            cardContainer(container, (c) => {
                const modeOptions: Array<{ value: string; label: string }> = [
                    { value: 'orbit', label: '轨道' },
                    { value: 'freefly', label: '自由飞行' },
                    { value: 'concert', label: '演唱会' },
                    { value: 'oneshot', label: '单拍' },
                ];
                if (vmdLoaded) {
                    modeOptions.push({ value: 'vmd', label: 'VMD 相机' });
                }

                addModeSlider(
                    c,
                    '相机模式',
                    modeOptions.map((o) => ({ value: o.value, label: o.label })),
                    currentMode,
                    (v) => {
                        if (v === currentMode) {
                            cameraExpandedMode = cameraExpandedMode ? null : currentMode;
                        } else {
                            switchCameraMode(v as CameraMode);
                            cameraExpandedMode = v === 'oneshot' ? null : (v as CameraMode);
                        }
                        refreshCameraLevel();
                    },
                    'lucide:camera',
                    undefined,
                    {
                        bind: () => getCameraMode(),
                    }
                );

                addSliderRow(
                    c,
                    '视场角',
                    getFov(),
                    0.3,
                    2,
                    0.05,
                    () => {},
                    'lucide:maximize-2',
                    (v) => {
                        setFov(v);
                        triggerAutoSave();
                    }
                );
            });

            // Auto Camera
            cardContainer(container, (c) => {
                addToggleRow(
                    c,
                    '自动运镜',
                    isAutoCameraEnabled(),
                    (v) => {
                        const bd = getProcBeatDetector();
                        setAutoCameraEnabled(v, bd ?? undefined);
                        refreshCameraLevel();
                    },
                    'lucide:video',
                    {
                        bind: () => isAutoCameraEnabled(),
                    }
                );
                if (isAutoCameraEnabled()) {
                    addSliderRow(
                        c,
                        '切换间隔（拍）',
                        getAutoCameraBeatsPerSwitch(),
                        1,
                        8,
                        1,
                        (v) => {
                            setAutoCameraBeatsPerSwitch(Math.round(v));
                        },
                        'lucide:timer',
                        undefined,
                        { bind: () => getAutoCameraBeatsPerSwitch() }
                    );
                }
            });

            // Camera params + VMD
            cardContainer(container, (c) => {
                const paramsContainer = document.createElement('div');
                paramsContainer.className = 'cs-params';
                const modeToExpand = cameraExpandedMode ?? currentMode;
                if (modeToExpand !== 'oneshot' && modeToExpand !== 'vmd') {
                    if (modeToExpand === 'orbit') {
                        renderOrbitParams(paramsContainer);
                    } else if (modeToExpand === 'freefly') {
                        renderFreeflyParams(paramsContainer);
                    } else if (modeToExpand === 'concert') {
                        renderConcertParams(paramsContainer);
                    }
                    c.appendChild(paramsContainer);
                }

                if (vmdLoaded) {
                    slideRow(c, 'lucide:trash-2', '清除相机 VMD', false, () => {
                        clearCameraVmd();
                        refreshCameraLevel();
                        setStatus('✓ 已清除相机 VMD', true);
                    });
                }

                slideRow(c, 'lucide:upload', '加载相机 VMD', false, () => {
                    setMotionBindingTargetId(null);
                    const level = stackRegistry.buildLevel!(
                        libraryRoot,
                        '相机 VMD',
                        (m) => m.format === 'vmd'
                    );
                    const menu = getMotionMenu();
                    if (menu) {
                        menu.push(level);
                    }
                });
            });
        },
    };
}

/** Build a parameter editing submenu for the given camera mode. */
export function buildCameraParamsLevel(mode: CameraMode): PopupLevel {
    return {
        label:
            mode === 'orbit'
                ? '轨道设置'
                : mode === 'freefly'
                  ? '自由飞行设置'
                  : mode === 'concert'
                    ? '演唱会设置'
                    : '相机设置',
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                if (mode === 'orbit') {
                    renderOrbitParams(c);
                } else if (mode === 'freefly') {
                    renderFreeflyParams(c);
                } else if (mode === 'concert') {
                    renderConcertParams(c);
                }
            });
        },
    };
}

function renderOrbitParams(container: HTMLElement): void {
    const p = getOrbitParams();
    addSliderRow(
        container,
