            // 求解质量（原名 求解迭代）
            {
                kind: 'slider',
                label: '求解质量',
                icon: 'lucide:repeat',
                target: 'physics:substeps',
                sliderValue: getSolverSubsteps(),
                sliderMin: 1,
                sliderMax: 4,
                sliderStep: 1,
                onSliderChange: (v: number) => {
                    setSolverSubsteps(v);
                },
            } as PopupRow,
            // 模拟速度
            {
                kind: 'slider',
                label: '模拟速度',
                icon: 'lucide:clock',
                target: 'physics:timescale',
                sliderValue: getTimeScale(),
                sliderMin: 0.1,
                sliderMax: 5,
                sliderStep: 0.1,
