/** 构建 WASM 物理子页（Bullet 骨髁物理信息 + 总开关） */
export function buildWasmPhysicsLevel(): PopupLevel {
    const id = focusedModelId;
    const inst = id ? modelManager.get(id) : null;
    const items: PopupRow[] = [];

    if (!id || !inst) {
        items.push({
            kind: 'action' as PopupRow['kind'],
            label: '请先加载模型',
            icon: 'lucide:info',
            target: 'wasm:none',
        } as PopupRow);
        return { label: 'WASM 物理', dir: '', items };
    }

    // 模型名 + 总开关
    items.push({
        kind: 'toggle',
        label: `物理解析（${inst.name}）`,
        icon: 'lucide:atom',
        target: 'wasm:master',
        toggleValue: inst.physicsEnabled,
        onToggleChange: (v) => {
            setModelPhysics(id, v);
            _patchToggle('wasm:master', v);
        },
    } as PopupRow);

    // 物理类别列表
    const categories = getPhysicsCategories(id);
    if (categories.length === 0) {
        items.push({
            kind: 'action' as PopupRow['kind'],
            label: '该模型无物理刚体',
            icon: 'lucide:info',
            target: 'wasm:nobody',
        } as PopupRow);
        return { label: 'WASM 物理', dir: '', items };
    }

    const CAT_LABELS: Record<string, string> = {
        skirt: '裙子',
        chest: '胸部',
        hair: '头发',
        accessory: '配件',
    };
    const CAT_ICONS: Record<string, string> = {
        skirt: 'lucide:shirt',
        chest: 'lucide:heart',
        hair: 'lucide:person-standing',
        accessory: 'lucide:gem',
    };

    for (const cat of categories) {
        const enabled = isPhysicsCategoryEnabled(id, cat);
        items.push({
            kind: 'toggle',
            label: CAT_LABELS[cat] || cat,
            icon: CAT_ICONS[cat] || 'lucide:settings',
            target: `wasm:cat:${cat}`,
            toggleValue: enabled,
            onToggleChange: (v) => {
                setPhysicsCategory(id, cat, v);
                _patchToggle(`wasm:cat:${cat}`, v);
            },
        } as PopupRow);
    }

    return { label: 'WASM 物理', dir: '', items };
}

