                            dirInput.value = dir;
                        }
                    })
                    .catch(() => {});
            });

            cardContainer(container, (c) => {
                addDangerRow(c, 'lucide:stop-circle', '停止监听', async () => {
                    const _r = await tryCatchStatus(() => StopWatchDir(), '✗ 停止监听失败');
