                `;
                c.appendChild(title);
                // 异步从 Go 端读取构建信息（ldflags 注入）
                GetBuildInfo()
                    .then((info) => {
                        const el = title.querySelector<HTMLElement>('[data-app-version]');
                        if (el) {
                            el.textContent = `v${info.version}`;
