// ============ 骨骼候选名 ============
const BONE_CENTER_CANDIDATES = ['センター', '全ての親', 'center', 'Center', 'Root', 'root'];
const BONE_UPPER_CANDIDATES = ['上半身', 'upper', 'Upper', '上半', '上半身2'];
const BONE_UPPER2_CANDIDATES = ['上半身2', 'upper2', 'Upper2', '上半身２'];
const BONE_NECK_CANDIDATES = ['首', 'neck', 'Neck', '首元'];
const BONE_HEAD_CANDIDATES = ['頭', 'head', 'Head', '頭頂'];

// 手臂 —— 加入 W 后缀变体
const BONE_LARM_CANDIDATES = [
    '左腕',
    '左腕W',
    '左arm',
    '左腕捩',
    'left arm',
    'LeftArm',
    'Left Arm',
];
const BONE_RARM_CANDIDATES = [
    '右腕',
    '右腕W',
    '右arm',
    '右腕捩',
    'right arm',
    'RightArm',
    'Right Arm',
];

// 手腕（手首）—— 若有则驱动
const BONE_WRIST_L_CANDIDATES = ['左手首', '左リスト', 'left wrist', 'LeftWrist'];
const BONE_WRIST_R_CANDIDATES = ['右手首', '右リスト', 'right wrist', 'RightWrist'];

// 肩部（包含 P / C 变体）
const BONE_SHOULDER_L_CANDIDATES = [
    '左肩',
    '左肩P',
    '左肩C',
    '左肩捩',
    'left shoulder',
    'LeftShoulder',
    'LeftShoulderP',
    'LeftShoulderC',
];
const BONE_SHOULDER_R_CANDIDATES = [
    '右肩',
    '右肩P',
    '右肩C',
    '右肩捩',
    'right shoulder',
    'RightShoulder',
    'RightShoulderP',
    'RightShoulderC',
];

// 躯干辅助
const BONE_WAIST_CANDIDATES = ['腰', 'waist', 'Waist', 'hips', 'Hips', 'hip'];
const BONE_ALLPARENT_CANDIDATES = ['全ての親', 'AllParent', 'all parent', 'root', 'Root'];
const BONE_GROOVE_CANDIDATES = ['グルーブ', 'groove', 'Groove'];

// 预留足IK（未启用）
const BONE_LEG_IK_L_CANDIDATES = ['左足IK', 'left leg ik', 'LeftLegIK'];
const BONE_LEG_IK_R_CANDIDATES = ['右足IK', 'right leg ik', 'RightLegIK'];

/** 从模型骨骼名列表中查找首个匹配且可 SJIS 编码的候选名，未找到时返回 null（跳过该骨骼）。 */
function _matchBone(actualBones: string[], candidates: string[]): string | null {
    for (const c of candidates) {
        if (actualBones.includes(c)) {
            if (canEncodeName(c)) {
                return c;
            }
            console.warn(`[procedural-motion] 骨骼 "${c}" 无法编码为 Shift-JIS，跳过`);
            return null; // 不继续 fallback 到其他候选（名不同，对应不同骨骼）
        }
    }
    return null;
}

// ============ Morph 候选名（扩充眨眼） ============
const MORPH_BLINK_CANDIDATES = [
    'まばたき',
    'blink',
    'Blink',
    '眨眼',
    'wink',
    'eye close',
    'EyeClose',
    '眼',
    '目',
    '閉眼',
];

const FPS = 30;
const MAX_FRAMES = 600; // 硬上限 20s，防止极端 speed/bpm 组合导致内存爆炸

/** 钳位旋转分量的安全辅助（四元数 w 计算前） */
const _clamp1 = (v: number) => Math.max(-1, Math.min(1, v));

// ============================================================================
//  Idle 生成（保持不变，柔和呼吸）
// ============================================================================
export function generateIdleVmd(
    state: ProcMotionState,
    morphNames: string[] = [],
    boneNames: string[] = []
): ArrayBuffer {
    const safeSpeed = Math.max(0.1, Math.min(10, state.speed));
    const loopFrames = Math.min(MAX_FRAMES, Math.round(120 / safeSpeed)); // 4s @ 30fps
    const intensity = state.intensity;
    const bones: BoneKeyFrame[] = [];
    const morphs: MorphKeyFrame[] = [];

    // ---------- 眨眼（伪随机间隔 2~8s，自然频率） ----------
    const blinkMorph = state.boneToggles.blink
        ? MORPH_BLINK_CANDIDATES.find((c) => morphNames.includes(c))
        : null;
    if (blinkMorph) {
        const blinkA = Math.round(60 / safeSpeed);
        const blinkB = Math.round(240 / safeSpeed);
        for (let t = blinkA, i = 0; t + 5 <= loopFrames; i++) {
            morphs.push({ name: blinkMorph, frame: t, weight: 0 });
            morphs.push({ name: blinkMorph, frame: t + 2, weight: 1 });
            morphs.push({ name: blinkMorph, frame: t + 5, weight: 0 });
            const step = blinkA + ((i * 17 + 3) % (blinkB - blinkA));
            t += Math.max(blinkA, step);
        }
        morphs.push({ name: blinkMorph, frame: loopFrames, weight: 0 });
    }

    // ---------- 骨骼匹配 ----------
    const centerBone = _matchBone(boneNames, BONE_CENTER_CANDIDATES);
    const upperBone = _matchBone(boneNames, BONE_UPPER_CANDIDATES);
    const upper2Bone = _matchBone(boneNames, BONE_UPPER2_CANDIDATES);
    const neckBone = _matchBone(boneNames, BONE_NECK_CANDIDATES);
    const headBone = _matchBone(boneNames, BONE_HEAD_CANDIDATES);
    const waistBone = _matchBone(boneNames, BONE_WAIST_CANDIDATES);
    const allParentBone = _matchBone(boneNames, BONE_ALLPARENT_CANDIDATES);
    const shoulderLBone = _matchBone(boneNames, BONE_SHOULDER_L_CANDIDATES);
    const shoulderRBone = _matchBone(boneNames, BONE_SHOULDER_R_CANDIDATES);
    const larmBone = _matchBone(boneNames, BONE_LARM_CANDIDATES);
    const rarmBone = _matchBone(boneNames, BONE_RARM_CANDIDATES);
    const wristLBone = _matchBone(boneNames, BONE_WRIST_L_CANDIDATES);
    const wristRBone = _matchBone(boneNames, BONE_WRIST_R_CANDIDATES);

    // ---------- 上半身呼吸 ----------
    const breathAmp = 0.03 * intensity;
    if ((upperBone || neckBone) && state.boneToggles.upper) {
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(phase) * breathAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (upperBone) {
                bones.push({
                    name: upperBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rx, 0, 0, w],
                });
            }
            if (neckBone) {
                const nrx = _clamp1(Math.sin(phase) * breathAmp * 0.6);
                const nw = Math.sqrt(Math.max(0, 1 - nrx * nrx));
                bones.push({
                    name: neckBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [nrx, 0, 0, nw],
                });
            }
        }
        if (upperBone) {
            bones.push({
                name: upperBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (neckBone) {
            bones.push({
                name: neckBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---------- 上半身2 ----------
    if (upper2Bone && state.boneToggles.upper2) {
        const amp2 = 0.015 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(phase * 0.7 + 0.3) * amp2);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            bones.push({
                name: upper2Bone,
                frame: f,
                position: [0, 0, 0],
                rotation: [rx, 0, 0, w],
            });
        }
        bones.push({
            name: upper2Bone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 腰 ----------
    if (waistBone && state.boneToggles.waist) {
        const waistAmp = 0.02 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rz = _clamp1(Math.sin(phase + 0.5) * waistAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: waistBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({
            name: waistBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 全ての親 ----------
    if (allParentBone && state.boneToggles.allParent) {
        const parentAmp = 0.005 * intensity;
        for (let f = 0; f <= loopFrames; f += 6) {
            const t = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(t * 0.2 + 1.1) * parentAmp);
            const rz = _clamp1(Math.sin(t * 0.3 + 2.3) * parentAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz));
            bones.push({
                name: allParentBone,
                frame: f,
                position: [0, 0, 0],
                rotation: [rx, 0, rz, w],
            });
        }
        bones.push({
            name: allParentBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- センター ----------
    if (centerBone && state.boneToggles.center) {
        const hasBreath = !!(upperBone || neckBone);
        const swayAmp = (hasBreath ? 0.04 : 0.1) * intensity;
        const microAmp = 0.03 * intensity;
        const bobAmp = (hasBreath ? 0.005 : 0.04) * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const slowPhase = phase * 0.5;
            const rz = _clamp1(Math.sin(slowPhase) * swayAmp);
            const rw = Math.sqrt(Math.max(0, 1 - rz * rz));
            const rx = _clamp1(Math.sin(phase * 0.37 + 0.5) * microAmp);
            const w = _clamp1(Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz)));
            const bobY = Math.sin(phase) * bobAmp;
            bones.push({
                name: centerBone,
                frame: f,
                position: [0, bobY, 0],
                rotation: [rx, 0, rz, w],
            });
        }
        bones.push({
            name: centerBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 頭 ----------
    if (headBone) {
        const headMicroAmp = 0.02 * intensity;
        for (let f = 0; f <= loopFrames; f += 6) {
            const t = (f / loopFrames) * Math.PI * 2;
            const rz = _clamp1(Math.sin(t * 0.43 + 1.2) * headMicroAmp);
            const rx = _clamp1(Math.sin(t * 0.29 + 3.7) * headMicroAmp * 0.7);
            const ry = _clamp1(Math.sin(t * 0.19 + 0.8) * headMicroAmp * 0.4);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz - rx * rx - ry * ry));
            bones.push({
                name: headBone,
                frame: f,
                position: [0, 0, 0],
                rotation: [rx, ry, rz, w],
            });
        }
        bones.push({
            name: headBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 手臂（自然钟摆） ----------
    if (larmBone || rarmBone) {
        const armAmp = 0.04 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rz = _clamp1(Math.sin(phase + 1.5) * armAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            if (larmBone) {
                bones.push({
                    name: larmBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [0, 0, rz, w],
                });
            }
            if (rarmBone) {
                bones.push({
                    name: rarmBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [0, 0, -rz, w],
                });
            }
        }
        if (larmBone) {
            bones.push({
                name: larmBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (rarmBone) {
            bones.push({
                name: rarmBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---------- 肩部 ----------
    if (shoulderLBone || shoulderRBone) {
        const shoulderAmp = 0.015 * intensity;
        const rotAmp = 0.01 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const breath = Math.sin(phase + 0.3);
            const yOffset = breath * shoulderAmp;
            const rz = _clamp1(Math.sin(phase + 0.1) * rotAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            if (shoulderLBone) {
                bones.push({
                    name: shoulderLBone,
                    frame: f,
                    position: [0, yOffset, 0],
                    rotation: [0, 0, rz, w],
                });
            }
            if (shoulderRBone) {
                const rOffset = Math.sin(phase + 0.5) * shoulderAmp;
                const rrz = _clamp1(Math.sin(phase + 0.4) * rotAmp);
                const rw = Math.sqrt(Math.max(0, 1 - rrz * rrz));
                bones.push({
                    name: shoulderRBone,
                    frame: f,
                    position: [0, rOffset, 0],
                    rotation: [0, 0, rrz, rw],
                });
            }
        }
        if (shoulderLBone) {
            bones.push({
                name: shoulderLBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (shoulderRBone) {
            bones.push({
                name: shoulderRBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---------- 手腕（若有） ----------
    if (wristLBone || wristRBone) {
        const wristAmp = 0.015 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(phase + 0.8) * wristAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (wristLBone) {
                bones.push({
                    name: wristLBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rx, 0, 0, w],
                });
            }
            if (wristRBone) {
                const rxR = _clamp1(Math.sin(phase + 1.1) * wristAmp);
                const wR = Math.sqrt(Math.max(0, 1 - rxR * rxR));
                bones.push({
                    name: wristRBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rxR, 0, 0, wR],
                });
            }
        }
        if (wristLBone) {
            bones.push({
                name: wristLBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (wristRBone) {
            bones.push({
                name: wristRBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // Idle 全部用 EASE_IN_OUT（柔和呼吸感）
    for (const b of bones) {
        b.interp = INTERP_EASE_IN_OUT;
    }
    return buildVmd(bones, morphs, PROC_VMD_NAME_IDLE);
}

// ============================================================================
//  Auto Dance 生成（显眼增强版）
// ============================================================================
export function generateAutoDanceVmd(
    state: ProcMotionState,
    bpm: number,
    morphNames: string[] = [],
    boneNames: string[] = []
): ArrayBuffer {
    const safeSpeed = Math.max(0.1, Math.min(10, state.speed));
    const clampedBpm = Math.max(60, Math.min(200, bpm));
    const beatFrames = Math.min(MAX_FRAMES, Math.round(((60 / clampedBpm) * FPS) / safeSpeed));
    const loopFrames = beatFrames * 8; // 8 拍循环（2 小节）
    const intensity = state.intensity;
    const bones: BoneKeyFrame[] = [];
    const morphs: MorphKeyFrame[] = [];

    // ---------- 眨眼（伪随机间隔 2~8s，同 idle） ----------
    const blinkMorph = MORPH_BLINK_CANDIDATES.find((c) => morphNames.includes(c));
    if (blinkMorph) {
        const blinkA = Math.round(60 / safeSpeed); // ~2s
        const blinkB = Math.round(240 / safeSpeed); // ~8s
        for (let t = blinkA, i = 0; t + 5 <= loopFrames; i++) {
            morphs.push({ name: blinkMorph, frame: t, weight: 0 });
            morphs.push({ name: blinkMorph, frame: t + 2, weight: 1 });
            morphs.push({ name: blinkMorph, frame: t + 5, weight: 0 });
            const step = blinkA + ((i * 17 + 3) % (blinkB - blinkA));
            t += Math.max(blinkA, step);
        }
        morphs.push({ name: blinkMorph, frame: loopFrames, weight: 0 });
    }

    // ---------- 骨骼匹配 ----------
    const centerBone = _matchBone(boneNames, BONE_CENTER_CANDIDATES);
    const upperBone = _matchBone(boneNames, BONE_UPPER_CANDIDATES);
    const upper2Bone = _matchBone(boneNames, BONE_UPPER2_CANDIDATES);
    const waistBone = _matchBone(boneNames, BONE_WAIST_CANDIDATES);
    const grooveBone = _matchBone(boneNames, BONE_GROOVE_CANDIDATES);
    const headBone = _matchBone(boneNames, BONE_HEAD_CANDIDATES);
    const larmBone = _matchBone(boneNames, BONE_LARM_CANDIDATES);
    const rarmBone = _matchBone(boneNames, BONE_RARM_CANDIDATES);
    const shoulderLBone = _matchBone(boneNames, BONE_SHOULDER_L_CANDIDATES);
    const shoulderRBone = _matchBone(boneNames, BONE_SHOULDER_R_CANDIDATES);
    const allParentBone = _matchBone(boneNames, BONE_ALLPARENT_CANDIDATES);
    const wristLBone = _matchBone(boneNames, BONE_WRIST_L_CANDIDATES);
    const wristRBone = _matchBone(boneNames, BONE_WRIST_R_CANDIDATES);
    const legIkLBone = _matchBone(boneNames, BONE_LEG_IK_L_CANDIDATES);
    const legIkRBone = _matchBone(boneNames, BONE_LEG_IK_R_CANDIDATES);

    // 预计算 sin/cos
    const sinVals: number[] = [];
    const cosVals: number[] = [];
    for (let f = 0; f <= loopFrames; f += 3) {
        const angle = (f / beatFrames) * Math.PI;
        sinVals[f] = Math.sin(angle);
        cosVals[f] = Math.cos(angle);
    }

    // ---------- 1. センター（大幅侧摆 + 旋转 + 弹跳） ----------
    if (centerBone && state.boneToggles.center) {
        const bodyAmp = 0.2 * intensity; // Y轴扭动
        const sideAmp = 0.12 * intensity; // Z轴侧摆（新增）
        const bobAmp = 0.06 * intensity; // 弹跳
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const c = cosVals[f];
            const ry = _clamp1(s * bodyAmp);
            const rz = _clamp1(c * sideAmp);
            const w = Math.sqrt(Math.max(0, 1 - ry * ry - rz * rz));
            const bob = Math.abs(s) * bobAmp;
            bones.push({
                name: centerBone,
                frame: f,
                position: [0, bob, 0],
                rotation: [0, ry, rz, w],
            });
        }
        bones.push({
            name: centerBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 2. 上半身（前倾后仰） ----------
    if (upperBone && state.boneToggles.upper) {
        const upperAmp = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f + Math.round(beatFrames / 2)] || 0;
            const rx = _clamp1(s * upperAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            bones.push({ name: upperBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, 0, w] });
        }
        bones.push({
            name: upperBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 3. 上半身2（扭转） ----------
    if (upper2Bone && state.boneToggles.upper2) {
        const amp2 = 0.06 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const ry = _clamp1(s * 0.6 * amp2);
            const w = Math.sqrt(Math.max(0, 1 - ry * ry));
            bones.push({
                name: upper2Bone,
                frame: f,
                position: [0, 0, 0],
                rotation: [0, ry, 0, w],
            });
        }
        bones.push({
            name: upper2Bone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 4. 腰（扭胯） ----------
    if (waistBone && state.boneToggles.waist) {
        const waistAmp = 0.2 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f + Math.round(beatFrames / 4)] || 0;
            const rz = _clamp1(-s * waistAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: waistBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({
            name: waistBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 5. 頭 ----------
    if (headBone && state.boneToggles.head) {
        const headAmp = 0.12 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const rz = _clamp1(-s * headAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: headBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({
            name: headBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 6. 手臂（大幅外展 + 前后甩动） ----------
    if ((larmBone || rarmBone) && state.boneToggles.arm) {
        const armAmpZ = 0.55 * intensity; // 外展幅度（Z轴）
        const armAmpX = 0.3 * intensity; // 前后甩动（X轴）
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const phase2 = cosVals[f + Math.round(beatFrames / 4)] || 0;
            if (larmBone) {
                const lz = _clamp1(s * armAmpZ);
                const lx = _clamp1(phase2 * armAmpX);
                const w = Math.sqrt(Math.max(0, 1 - lz * lz - lx * lx));
                bones.push({
                    name: larmBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [lx, 0, lz, w],
                });
            }
            if (rarmBone) {
                const rz = _clamp1(-s * armAmpZ);
                const rx = _clamp1(phase2 * armAmpX);
                const w = Math.sqrt(Math.max(0, 1 - rz * rz - rx * rx));
                bones.push({
                    name: rarmBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rx, 0, rz, w],
                });
            }
        }
        if (larmBone) {
            bones.push({
                name: larmBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (rarmBone) {
            bones.push({
                name: rarmBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---------- 7. グルーブ ----------
    if (grooveBone && state.boneToggles.groove) {
        const grooveAmp = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const bob = Math.abs(s) * 0.08 * intensity;
            const ry = _clamp1(s * grooveAmp);
            const w = Math.sqrt(Math.max(0, 1 - ry * ry));
            bones.push({
                name: grooveBone,
                frame: f,
                position: [0, bob, 0],
                rotation: [0, ry, 0, w],
            });
        }
        bones.push({
            name: grooveBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 8. 肩部（耸肩） ----------
    if ((shoulderLBone || shoulderRBone) && state.boneToggles.shoulder) {
        const shoulderUpAmp = 0.1 * intensity;
        const shoulderRotAmp = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const up = Math.abs(s) * shoulderUpAmp;
            const rot = _clamp1(s * shoulderRotAmp);
            const w = Math.sqrt(Math.max(0, 1 - rot * rot));
            if (shoulderLBone) {
                bones.push({
                    name: shoulderLBone,
                    frame: f,
                    position: [0, up, 0],
                    rotation: [0, 0, rot, w],
                });
            }
            if (shoulderRBone) {
                bones.push({
                    name: shoulderRBone,
                    frame: f,
                    position: [0, up, 0],
                    rotation: [0, 0, rot, w],
                });
            }
        }
        if (shoulderLBone) {
            bones.push({
                name: shoulderLBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (shoulderRBone) {
            bones.push({
                name: shoulderRBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---------- 9. 全ての親 ----------
    if (allParentBone && state.boneToggles.allParent) {
        const parentAmp = 0.02 * intensity;
        for (let f = 0; f <= loopFrames; f += 6) {
            const t = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(t * 0.7 + 1.1) * parentAmp);
            const rz = _clamp1(Math.sin(t * 0.5 + 2.3) * parentAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz));
            bones.push({
                name: allParentBone,
                frame: f,
                position: [0, 0, 0],
                rotation: [rx, 0, rz, w],
            });
        }
        bones.push({
            name: allParentBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 10. 手腕（节拍下压 + 侧摆） ----------
    if ((wristLBone || wristRBone) && state.boneToggles.wrist) {
        const wristAmpX = 0.35 * intensity;
        const wristAmpZ = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const rx = _clamp1(Math.abs(s) * wristAmpX);
            const rz = _clamp1(cosVals[f] * wristAmpZ);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz));
            if (wristLBone) {
                bones.push({
                    name: wristLBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rx, 0, rz, w],
                });
            }
            if (wristRBone) {
                const rzR = _clamp1(-cosVals[f] * wristAmpZ);
                const wR = Math.sqrt(Math.max(0, 1 - rx * rx - rzR * rzR));
                bones.push({
                    name: wristRBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rx, 0, rzR, wR],
                });
            }
        }
        if (wristLBone) {
            bones.push({
                name: wristLBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (wristRBone) {
            bones.push({
                name: wristRBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---------- 11. 足IK（基础踏步） ----------
    if (state.boneToggles.footIk && (legIkLBone || legIkRBone)) {
        const stepAmp = 0.08 * intensity; // Z轴前后位移
        const liftAmp = 0.03 * intensity; // Y轴抬脚（只抬不沉，防穿地）
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            if (legIkLBone) {
                const lz = _clamp1(s * stepAmp);
                const ly = Math.max(0, s) * liftAmp; // 只抬不沉
                bones.push({
                    name: legIkLBone,
                    frame: f,
                    position: [0, ly, lz],
                    rotation: [0, 0, 0, 1],
                });
            }
            if (legIkRBone) {
                const rz = _clamp1(-s * stepAmp);
                const ry = Math.max(0, -s) * liftAmp; // 反相
                bones.push({
                    name: legIkRBone,
                    frame: f,
                    position: [0, ry, rz],
                    rotation: [0, 0, 0, 1],
                });
            }
        }
        if (legIkLBone) {
            bones.push({
                name: legIkLBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (legIkRBone) {
            bones.push({
                name: legIkRBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ========== 🎭 表情情绪轮（动态扫描可用 morph） ==========
    // 不再硬编码少数模型专有名字，而是按语义自动分类可用 morph
    if (!state.boneToggles.emotion) {
        // 表情情绪轮已关闭，跳过
    } else {
        // 忽略纯口型/音素/眨眼 morph，专注表情 morph
        const BLACKLIST_PATTERNS = [
            'まばたき',
            'blink',
            '眨眼',
            'wink',
            'ウィンク',
            'あ',
            'い',
            'う',
            'え',
            'お',
            'a ',
            'i ',
            'u ',
            'e ',
            'o ',
        ];

        // 按候选关键词给每个 morph 打分，选出最可能的"表情型" morph
        function _scoreMorph(name: string, keywords: string[]): number {
            const nameLC = name.toLowerCase();
            let score = 0;
            for (const kw of keywords) {
                if (name.includes(kw) || nameLC.includes(kw.toLowerCase())) {
                    score += 10;
                }
            }
            // 惩罚音素/眨眼这类非表情 morph
            for (const bp of BLACKLIST_PATTERNS) {
                if (name.includes(bp)) {
                    score -= 10;
                }
            }
            return score;
        }

        // 候选表情映射：luc (表情类别) → 候选关键词列表
        const EMOTION_CANDIDATES: Record<string, string[]> = {
            smile: ['にこり', '笑い', 'smile', 'えがお', 'happy', '喜び', '嬉しい', 'よろこび'],
            sad: ['悲しみ', 'sad', 'cry', '泣き', '哀しみ', 'かなしみ'],
            angry: ['怒り', 'angry', 'いかり', 'むっ', 'まゆ'],
            surprise: ['びっくり', 'surprise', 'おどろき', '驚き', 'wonder', 'わお'],
            worry: ['困る', 'worry', 'こまる', '悩み', 'なやみ', '困惑'],
            serious: ['真面目', 'serious', 'まじめ', 'じと目', 'じと'],
            shy: ['照れ', 'shy', 'てれ', 'はにかみ', '恥ずかしい'],
            wink: ['ウィンク', 'wink', 'ういんく', 'win'],
        };

        // 为每个表情类别选出得分最高的 morph
        const emotionMorphs = new Map<string, string>();
        for (const [category, keywords] of Object.entries(EMOTION_CANDIDATES)) {
            let bestName: string | null = null;
            let bestScore = 0;
            for (const mName of morphNames) {
                const score = _scoreMorph(mName, keywords);
                if (score > bestScore) {
                    bestScore = score;
                    bestName = mName;
                }
            }
            if (bestName) {
                emotionMorphs.set(category, bestName);
            }
        }

        // 验证 morph 名能否被 Shift-JIS 编码（不能编码的在 VMD 中会乱码，babylon-mmd 找不到匹配）
        for (const [k, n] of emotionMorphs) {
            if (!canEncodeName(n)) {
                console.log(
                    `[procedural-motion] 表情 morph "${k}=${n}" 无法编码为 Shift-JIS，跳过`
                );
                emotionMorphs.delete(k);
            }
        }

        // 如果没有找到任何表情 morph，跳过所有情绪逻辑
        const foundEmotions = Array.from(emotionMorphs.entries()).filter(([k]) => k !== 'wink');
        if (foundEmotions.length > 0) {
            console.log(
                `[procedural-motion] 表情 morph 匹配: [${foundEmotions.map(([k, n]) => `${k}=${n}`).join(', ')}]`
            );
            // 微表情专用（surprise 和 wink 短闪用，不加入主轮换）
            const surpriseMorph = emotionMorphs.get('surprise') ?? null;
            const winkMorph = emotionMorphs.get('wink') ?? null;

            // 1. 主表情轮换：每 1 小节（4 拍）切换一种情绪，权重 0.5~0.8
            const cycleBeats = 4; // 4 拍切换一次
            const cycleFrames = beatFrames * cycleBeats;
            const cycleCount = Math.min(foundEmotions.length, Math.floor(loopFrames / cycleFrames));
            const availEmo = foundEmotions.slice(0, cycleCount);

            for (let ci = 0; ci < availEmo.length; ci++) {
                const [_, morphName] = availEmo[ci];
                const start = cycleFrames * ci;
                const end = Math.min(start + cycleFrames - 1, loopFrames);
                // 顺滑切入切出：1/4 周期淡入，1/4 周期淡出
                const fadeIn = Math.floor(beatFrames * 0.3);
                const fadeOut = Math.max(end - Math.floor(beatFrames * 0.3), start + fadeIn);
                const weight = 0.5 + 0.3 * intensity;
                // 淡入段
                morphs.push({ name: morphName, frame: start, weight: 0 });
                morphs.push({ name: morphName, frame: start + fadeIn, weight: weight });
                // 维持段
                morphs.push({ name: morphName, frame: fadeOut, weight: weight });
                // 淡出段
                morphs.push({ name: morphName, frame: end, weight: 0 });
            }

            // 2. 微表情点缀：在每小节强拍附近随机闪现 surprise 或 wink（仅 6~8 帧）
            const accentMorph = surpriseMorph ?? winkMorph;
            if (accentMorph) {
                const measureCount = Math.min(4, Math.floor(loopFrames / (beatFrames * 2)));
                for (let m = 0; m < measureCount; m++) {
                    const base = m * beatFrames * 2;
                    const rand = (m * 7 + 3) % 10;
                    if (rand < 3) {
                        const t = base + Math.floor(beatFrames * 0.2);
                        if (t + 6 <= loopFrames) {
                            const w = 0.5 + 0.3 * intensity;
                            morphs.push({ name: accentMorph, frame: t, weight: 0 });
                            morphs.push({ name: accentMorph, frame: t + 1, weight: w });
                            morphs.push({ name: accentMorph, frame: t + 3, weight: w });
                            morphs.push({ name: accentMorph, frame: t + 6, weight: 0 });
                        }
                    }
                }
            }

            // 3. 害羞表情在副歌位置（倒数 2 小节）插入
            const shyMorph = emotionMorphs.get('shy') ?? null;
            if (shyMorph) {
                const shyStart = loopFrames - beatFrames * 4;
                if (shyStart > 0) {
                    morphs.push({ name: shyMorph, frame: shyStart, weight: 0 });
                    morphs.push({
                        name: shyMorph,
                        frame: shyStart + Math.floor(beatFrames * 0.5),
                        weight: 0.6 * intensity,
                    });
                    morphs.push({
                        name: shyMorph,
                        frame: shyStart + beatFrames * 2,
                        weight: 0.6 * intensity,
                    });
                    morphs.push({
                        name: shyMorph,
                        frame: shyStart + beatFrames * 2 + 2,
                        weight: 0,
                    });
                }
            }
        } else {
            console.warn('[procedural-motion] 未找到任何表情 morph，跳过情绪轮');
        }
    } // ← 表情情绪轮 else 块结束
    // 按骨骼类型分配插值曲线（受 interpOverride 控制）
    const _override = state.interpOverride;
    let _overrideInterp: typeof INTERP_SHARP | null = null;
    if (_override === 'sharp') {
        _overrideInterp = INTERP_SHARP;
    } else if (_override === 'ease-in-out') {
        _overrideInterp = INTERP_EASE_IN_OUT;
    } else if (_override === 'ease-out') {
        _overrideInterp = INTERP_EASE_OUT;
    }

    for (const b of bones) {
        if (_overrideInterp) {
            b.interp = _overrideInterp;
            continue;
        }
        const n = b.name;
        // 手臂摆动 → EASE_OUT（快速启动慢停）
        if (n === larmBone || n === rarmBone) {
            b.interp = INTERP_EASE_OUT;
        } else if (n === centerBone || n === waistBone || n === legIkLBone || n === legIkRBone) { // 中心弹跳 / 腰扭转 / 足IK踏步 → SHARP（锐利节拍感）
            b.interp = INTERP_SHARP;
        } else { // 其余（肩/手腕/头/上半身/上半身2/全親/グルーブ）→ EASE_IN_OUT
            b.interp = INTERP_EASE_IN_OUT;
        }
    }
    return buildVmd(bones, morphs, PROC_VMD_NAME_AUTODANCE);
}

// ============================================================================
//  Lifelike 生成（极微叠加层 — 叠加在任何动画上增加生命力）
//  与 Idle 的区别：Idle 替换动画，Lifelike 叠加在已有动画上。
//  特点：幅度极小、多频率叠加、不干扰主动画。
// ============================================================================
export function generateLifelikeVmd(
    state: ProcMotionState,
    morphNames: string[] = [],
    boneNames: string[] = []
): ArrayBuffer {
    const safeSpeed = Math.max(0.1, Math.min(10, state.speed));
    const intensity = state.lifelikeIntensity;
    // 10s 循环（足够长避免明显循环感）
    const loopFrames = Math.min(MAX_FRAMES, Math.round(300 / safeSpeed));
    const bones: BoneKeyFrame[] = [];
    const morphs: MorphKeyFrame[] = [];

    // ---------- 骨骼匹配 ----------
    const centerBone = _matchBone(boneNames, BONE_CENTER_CANDIDATES);
    const upperBone = _matchBone(boneNames, BONE_UPPER_CANDIDATES);
    const upper2Bone = _matchBone(boneNames, BONE_UPPER2_CANDIDATES);
    const neckBone = _matchBone(boneNames, BONE_NECK_CANDIDATES);
    const headBone = _matchBone(boneNames, BONE_HEAD_CANDIDATES);
    const waistBone = _matchBone(boneNames, BONE_WAIST_CANDIDATES);
    const allParentBone = _matchBone(boneNames, BONE_ALLPARENT_CANDIDATES);
    const shoulderLBone = _matchBone(boneNames, BONE_SHOULDER_L_CANDIDATES);
    const shoulderRBone = _matchBone(boneNames, BONE_SHOULDER_R_CANDIDATES);
    const larmBone = _matchBone(boneNames, BONE_LARM_CANDIDATES);
    const rarmBone = _matchBone(boneNames, BONE_RARM_CANDIDATES);
    const wristLBone = _matchBone(boneNames, BONE_WRIST_L_CANDIDATES);
    const wristRBone = _matchBone(boneNames, BONE_WRIST_R_CANDIDATES);

    // ---- 呼吸（上半身 + 颈部，双频叠加更自然） ----
    if ((upperBone || neckBone) && state.boneToggles.upper) {
        const breathAmp = 0.015 * intensity; // 比 idle 的 0.03 小一半
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            // 双频叠加：主呼吸 ~4s + 次呼吸 ~6s
            const breathMain = Math.sin(t * Math.PI * 2) * breathAmp;
            const breathSub = Math.sin(t * Math.PI * 2 * 0.67 + 0.8) * breathAmp * 0.4;
            const rx = _clamp1(breathMain + breathSub);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (upperBone) {
                bones.push({
                    name: upperBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rx, 0, 0, w],
                });
            }
            if (neckBone) {
                const nrx = _clamp1(rx * 0.5);
                const nw = Math.sqrt(Math.max(0, 1 - nrx * nrx));
                bones.push({
                    name: neckBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [nrx, 0, 0, nw],
                });
            }
        }
        if (upperBone) {
            bones.push({
                name: upperBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (neckBone) {
            bones.push({
                name: neckBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---- 上半身2（微扭转，不规则频率） ----
    if (upper2Bone && state.boneToggles.upper2) {
        const amp2 = 0.008 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.43 + 1.2) * amp2);
            const ry = _clamp1(Math.sin(t * Math.PI * 2 * 0.31 + 0.5) * amp2 * 0.6);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - ry * ry));
            bones.push({
                name: upper2Bone,
                frame: f,
                position: [0, 0, 0],
                rotation: [rx, ry, 0, w],
            });
        }
        bones.push({
            name: upper2Bone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---- 重心漂移（极慢不规则漂移，像真人站立时的重心调整） ----
    if (centerBone && state.boneToggles.center) {
        const driftAmp = 0.012 * intensity;
        const bobAmp = 0.003 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            // 三个不相干频率叠加，避免周期感
            const rz = _clamp1(
                Math.sin(t * Math.PI * 2 * 0.15 + 0.3) * driftAmp * 0.6 +
                    Math.sin(t * Math.PI * 2 * 0.23 + 1.7) * driftAmp * 0.3 +
                    Math.sin(t * Math.PI * 2 * 0.37 + 2.9) * driftAmp * 0.1
            );
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.11 + 0.9) * driftAmp * 0.3);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz));
            const bobY = Math.sin(t * Math.PI * 2 * 0.5) * bobAmp;
            bones.push({
                name: centerBone,
                frame: f,
                position: [0, bobY, 0],
                rotation: [rx, 0, rz, w],
            });
        }
        bones.push({
            name: centerBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---- 头部（微摆，多频不规则） ----
    if (headBone && state.boneToggles.head) {
        const headAmp = 0.01 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rz = _clamp1(
                Math.sin(t * Math.PI * 2 * 0.19 + 0.7) * headAmp * 0.5 +
                    Math.sin(t * Math.PI * 2 * 0.31 + 2.1) * headAmp * 0.3
            );
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.13 + 1.4) * headAmp * 0.3);
            const ry = _clamp1(Math.sin(t * Math.PI * 2 * 0.09 + 0.3) * headAmp * 0.2);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz - rx * rx - ry * ry));
            bones.push({
                name: headBone,
                frame: f,
                position: [0, 0, 0],
                rotation: [rx, ry, rz, w],
            });
        }
        bones.push({
            name: headBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---- 腰（微扭，极低频） ----
    if (waistBone && state.boneToggles.waist) {
        const waistAmp = 0.008 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rz = _clamp1(Math.sin(t * Math.PI * 2 * 0.17 + 1.1) * waistAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: waistBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({
            name: waistBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---- 肩部（微起伏，模拟呼吸联动） ----
    if ((shoulderLBone || shoulderRBone) && state.boneToggles.shoulder) {
        const shoulderAmp = 0.006 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const yL = Math.sin(t * Math.PI * 2 + 0.3) * shoulderAmp;
            const yR = Math.sin(t * Math.PI * 2 + 0.7) * shoulderAmp * 0.8;
            const rzL = _clamp1(Math.sin(t * Math.PI * 2 * 0.5 + 0.1) * shoulderAmp * 0.3);
            const rzR = _clamp1(Math.sin(t * Math.PI * 2 * 0.5 + 0.5) * shoulderAmp * 0.3);
            const wL = Math.sqrt(Math.max(0, 1 - rzL * rzL));
            const wR = Math.sqrt(Math.max(0, 1 - rzR * rzR));
            if (shoulderLBone) {
                bones.push({
                    name: shoulderLBone,
                    frame: f,
                    position: [0, yL, 0],
                    rotation: [0, 0, rzL, wL],
                });
            }
            if (shoulderRBone) {
                bones.push({
                    name: shoulderRBone,
                    frame: f,
                    position: [0, yR, 0],
                    rotation: [0, 0, rzR, wR],
                });
            }
        }
        if (shoulderLBone) {
            bones.push({
                name: shoulderLBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (shoulderRBone) {
            bones.push({
                name: shoulderRBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---- 手臂（极微自然钟摆，不干扰主动画） ----
    if ((larmBone || rarmBone) && state.boneToggles.arm) {
        const armAmp = 0.012 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rz = _clamp1(Math.sin(t * Math.PI * 2 * 0.25 + 1.5) * armAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            if (larmBone) {
                bones.push({
                    name: larmBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [0, 0, rz, w],
                });
            }
            if (rarmBone) {
                bones.push({
                    name: rarmBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [0, 0, -rz, w],
                });
            }
        }
        if (larmBone) {
            bones.push({
                name: larmBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (rarmBone) {
            bones.push({
                name: rarmBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---- 手腕（极微晃动） ----
    if ((wristLBone || wristRBone) && state.boneToggles.wrist) {
        const wristAmp = 0.008 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.33 + 0.8) * wristAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (wristLBone) {
                bones.push({
                    name: wristLBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rx, 0, 0, w],
                });
            }
            if (wristRBone) {
                const rxR = _clamp1(Math.sin(t * Math.PI * 2 * 0.33 + 1.1) * wristAmp);
                const wR = Math.sqrt(Math.max(0, 1 - rxR * rxR));
                bones.push({
                    name: wristRBone,
                    frame: f,
                    position: [0, 0, 0],
                    rotation: [rxR, 0, 0, wR],
                });
            }
        }
        if (wristLBone) {
            bones.push({
                name: wristLBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
        if (wristRBone) {
            bones.push({
                name: wristRBone,
                frame: loopFrames,
                position: [0, 0, 0],
                rotation: [0, 0, 0, 1],
            });
        }
    }

    // ---- 全ての親（极微整体晃动） ----
    if (allParentBone && state.boneToggles.allParent) {
        const parentAmp = 0.003 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const t = f / loopFrames;
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.08 + 1.1) * parentAmp);
            const rz = _clamp1(Math.sin(t * Math.PI * 2 * 0.12 + 2.3) * parentAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz));
            bones.push({
                name: allParentBone,
                frame: f,
                position: [0, 0, 0],
                rotation: [rx, 0, rz, w],
            });
        }
        bones.push({
            name: allParentBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---- 微表情（偶尔的极微 morph 变化） ----
    if (state.boneToggles.emotion) {
        const BLINK_BLACKLIST = ['まばたき', 'blink', '眨眼', 'wink'];
        const emotionCandidates = morphNames.filter(
            (m) => !BLINK_BLACKLIST.some((b) => m.includes(b))
        );
        // 选取前 3 个可用 morph 做极微闪烁
        const selected = emotionCandidates.slice(0, 3);
        for (let mi = 0; mi < selected.length; mi++) {
            const mName = selected[mi];
            // 每个 morph 在不同时间点做极短闪烁（2~4帧）
            const offset = (mi * loopFrames) / selected.length;
            const flickerStart = Math.round(offset + loopFrames * 0.1);
            if (flickerStart + 4 <= loopFrames) {
                const w = 0.15 * intensity;
                morphs.push({ name: mName, frame: flickerStart, weight: 0 });
                morphs.push({ name: mName, frame: flickerStart + 1, weight: w });
                morphs.push({ name: mName, frame: flickerStart + 3, weight: w });
                morphs.push({ name: mName, frame: flickerStart + 4, weight: 0 });
            }
        }
    }

    // 全部用 EASE_IN_OUT（柔和）
    for (const b of bones) {
        b.interp = INTERP_EASE_IN_OUT;
    }
    return buildVmd(bones, morphs, PROC_VMD_NAME_LIFELIKE);
}

// ============================================================================
//  状态判断函数（不变）
// ============================================================================
export function shouldAutoDance(audioPlaying: boolean, mode: ProcMotionMode): boolean {
    if (mode === 'idle') {
        return false;
    }
    if (mode === 'autodance') {
        return true;
    }
    return audioPlaying; // 'off' = auto mode
}

export function shouldIdle(
    audioPlaying: boolean,
    hasUserVmd: boolean,
    mode: ProcMotionMode
): boolean {
    return (
        !audioPlaying && !hasUserVmd && (mode === 'idle' || mode === 'off' || mode === 'autodance')
    );
}

// [doc:architecture] Outfit Overlay — FBX 布料叠加层加载/骨骼重定向/生命周期
// 职责: 从 MD 导出的 FBX 加载叠加 mesh，绑定到 PMX skeleton，管理隐藏/恢复

import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { Skeleton } from '@babylonjs/core/Bones/skeleton';
import { ImportMeshAsync } from '@babylonjs/core/Loading/sceneLoader';
import type { Scene } from '@babylonjs/core/scene';

import { type ModelInstance } from '../core/config';

// ============================================================
// URL helpers
// ============================================================

function _encodePath(path: string): string {
    return path
        .replace(/\\/g, '/')
        .split('/')
        .map((p) => encodeURIComponent(p))
        .join('/');
}

// ============================================================
// Skeleton retargeting
// ============================================================

/**
 * 将 FBX skeleton 的 bone 按 name 匹配到 PMX runtimeBones，
 * 重建 bone weight index 映射，使 FBX mesh 跟随 PMX 骨骼动画。
 *
 * @returns true = 成功重定向，false = 匹配率过低，应降级为静态叠加
 */
function retargetSkeleton(inst: ModelInstance, fbxMeshes: Mesh[]): boolean {
    const pmxModel = inst.mmdModel;
    if (!pmxModel) {
        return false;
    }
    // 找到第一个有 skeleton 的 FBX mesh
    // eslint-disable-next-line eqeqeq -- 惯用法:同时排除 null 与 undefined
    const skinned = fbxMeshes.find((m) => m.skeleton != null);
    if (!skinned || !skinned.skeleton) {
        return false;
    }
    const fbxSkeleton = skinned.skeleton;

    // 建立 FBX bone name → PMX runtimeBone 索引的映射
    const pmxRuntimeBones = pmxModel.runtimeBones;
    const pmxBoneNameToIdx = new Map<string, number>();
    for (let i = 0; i < pmxRuntimeBones.length; i++) {
        pmxBoneNameToIdx.set(pmxRuntimeBones[i].name, i);
    }

    // 匹配 FBX bones 到 PMX bones
    const fbxToPmxBoneIdx = new Map<number, number>(); // fbx bone index → pmx bone index
    let matchCount = 0;
    for (let i = 0; i < fbxSkeleton.bones.length; i++) {
        const fbxBone = fbxSkeleton.bones[i];
        const pmxIdx = pmxBoneNameToIdx.get(fbxBone.name);
        if (pmxIdx !== undefined) {
            fbxToPmxBoneIdx.set(i, pmxIdx);
            matchCount++;
        }
    }

    const matchRate = matchCount / fbxSkeleton.bones.length;
    if (matchRate < 0.5) {
        console.warn(
            `[outfit-overlay] Skeleton retarget failed: only ${matchCount}/${fbxSkeleton.bones.length} bones matched (${Math.round(matchRate * 100)}%)`
        );
        return false;
    }

    console.info(
        `[outfit-overlay] Skeleton retarget: ${matchCount}/${fbxSkeleton.bones.length} bones matched (${Math.round(matchRate * 100)}%)`
    );

    // 获取 PMX 的 Babylon.js skeleton（从 rootMesh metadata 获取）
    const rootMeta = inst.rootMesh.metadata as { skeleton?: Skeleton } | undefined;
    const pmxSkeleton = rootMeta?.skeleton;
    if (!pmxSkeleton) {
        console.warn('[outfit-overlay] PMX model has no skeleton in metadata');
        return false;
    }

    // 对每个 skinned mesh：重建 bone weight index 映射
    for (const mesh of fbxMeshes) {
        if (!mesh.skeleton) {
            continue;
        }

        // 获取 mesh 的 bone weight buffer
        const matricesWeights = mesh.getVerticesData('matricesWeights');
        const matricesIndices = mesh.getVerticesData('matricesIndices');
        if (!matricesWeights || !matricesIndices) {
            continue;
        }

        // 重建 matricesIndices：FBX bone index → PMX bone index
        const newIndices = new Float32Array(matricesIndices.length);
        let remapped = 0;
        for (let i = 0; i < matricesIndices.length; i++) {
            const fbxIdx = matricesIndices[i];
            const pmxIdx = fbxToPmxBoneIdx.get(fbxIdx);
            if (pmxIdx !== undefined) {
                newIndices[i] = pmxIdx;
                remapped++;
            } else {
                // 未匹配的 bone → 映射到根 bone (index 0)
                newIndices[i] = 0;
            }
        }

        // 更新 vertex buffer
        mesh.setVerticesData('matricesIndices', newIndices);

        // 切换 skeleton 引用
        mesh.skeleton = pmxSkeleton;
    }

    // 释放 FBX 原 skeleton（不再被任何 mesh 引用）
    try {
        fbxSkeleton.dispose();
    } catch {
        // ignore disposal errors
    }

    return true;
}

// ============================================================
// Load overlay
// ============================================================

/**
 * 加载 FBX overlay 并尝试绑定到模型 skeleton。
 * @param inst 模型实例
 * @param meshFile FBX 相对路径（相对模型目录）
 * @param scene Babylon scene
 * @returns 加载的 mesh 列表，失败返回空数组
 */
export async function loadOverlay(
    inst: ModelInstance,
    meshFile: string,
    scene: Scene
): Promise<Mesh[]> {
    const url = `http://127.0.0.1:${inst.port}/${_encodePath(meshFile)}`;
    console.info(`[outfit-overlay] Loading FBX overlay: ${meshFile}`);

    try {
        const result = await ImportMeshAsync(url, scene);
        const meshes = result.meshes.filter((m): m is Mesh => m instanceof Mesh);

        if (meshes.length === 0) {
            console.warn('[outfit-overlay] FBX loaded but no meshes found');
            return [];
        }

        // 尝试骨骼重定向
        let skeletonOk = false;
        if (inst.mmdModel) {
            skeletonOk = retargetSkeleton(inst, meshes);
        }

        if (!skeletonOk) {
            // 降级：静态叠加，parent 到 rootMesh
            console.info('[outfit-overlay] Falling back to static overlay (parent rootMesh)');
            for (const m of meshes) {
                m.parent = inst.rootMesh;
            }
        }

        // 标记为 overlay（避免被 outfit 纹理替换逻辑处理）
        for (const m of meshes) {
            m.metadata = { ...(m.metadata ?? {}), outfitOverlay: true };
        }

        inst._overlayMeshes = meshes;
        return meshes;
    } catch (err) {
        console.error('[outfit-overlay] Failed to load FBX overlay:', err);
        return [];
    }
}

// ============================================================
// Material hide/restore
// ============================================================

/**
 * 隐藏指定材质名的 PMX mesh（保存原始可见性用于恢复）。
 */
export function hideMaterials(inst: ModelInstance, materialNames: string[]): void {
    if (!materialNames || materialNames.length === 0) {
        return;
    }

    const nameSet = new Set(materialNames.map((n) => n.toLowerCase()));

    if (!inst._origMaterialVisibility) {
        inst._origMaterialVisibility = new Map();
    }

    for (let i = 0; i < inst.meshes.length; i++) {
        const mesh = inst.meshes[i];
        const mat = mesh.material;
        if (!mat) {
            continue;
        }

        // 按材质名匹配
        if (nameSet.has(mat.name.toLowerCase())) {
            // 只在第一次保存原始可见性
            if (!inst._origMaterialVisibility.has(i)) {
                inst._origMaterialVisibility.set(i, mesh.isEnabled());
            }
            mesh.setEnabled(false);
        }
    }
}

/**
 * 恢复被 hideMaterials 隐藏的 PMX mesh 可见性。
 */
export function restoreMaterials(inst: ModelInstance): void {
    if (!inst._origMaterialVisibility) {
        return;
    }

    for (const [idx, wasVisible] of inst._origMaterialVisibility) {
        if (idx < inst.meshes.length) {
            inst.meshes[idx].setEnabled(wasVisible);
        }
    }
    inst._origMaterialVisibility = undefined;
}

// ============================================================
// Dispose
// ============================================================

/**
 * 释放 overlay mesh 并清理引用。
 */
export function disposeOverlay(inst: ModelInstance): void {
    if (!inst._overlayMeshes) {
        return;
    }

    // 获取 PMX skeleton 用于比较（避免误释放共享 skeleton）
    const rootMeta = inst.rootMesh.metadata as { skeleton?: Skeleton } | undefined;
    const pmxSkeleton = rootMeta?.skeleton;

    const disposedSkeletons = new Set<Skeleton>();
    for (const mesh of inst._overlayMeshes) {
        try {
            // 如果 mesh 有独立 skeleton（未重定向成功），先释放
            if (
                mesh.skeleton &&
                mesh.skeleton !== pmxSkeleton &&
                !disposedSkeletons.has(mesh.skeleton)
            ) {
                disposedSkeletons.add(mesh.skeleton);
                mesh.skeleton.dispose();
            }
            mesh.dispose();
        } catch {
            // ignore disposal errors
        }
    }
    inst._overlayMeshes = undefined;
}

// [doc:architecture] Cloth Manager — 布料模拟控制器
// 从 scene-menu.ts 提取，职责: 布料创建/销毁/重建
// UI 层通过 toggleCloth / recreateCloth 调用，不再寄生菜单文件

import { SdfCollider, DEFAULT_BODY_CAPSULES } from './xpbd-collider';
import type { CapsuleSpec } from './xpbd-collider';
import {
    createCloth,
    buildClothUpdateFn,
    setDebugUpdateFn,
    DEFAULT_CLOTH_CONFIG,
} from './xpbd-cloth';
import { XpbdRenderer } from './xpbd-renderer';
import { scene, modelManager } from '../scene/scene';
import { focusedModelId, envState, setStatus } from '../core/config';

/** 当前布料的碰撞体引用 */
let _currentCollider: SdfCollider | null = null;

/** 当前布料重力倍率（与 WASM 共用同一 slider，独立追踪避免耦合） */
let _clothGravity = 1.0;

/** 调试可视化渲染器 */
let _renderer: XpbdRenderer | null = null;

/** 为当前聚焦模型创建布料 */
function _createClothForFocusedModel(): void {
    const id = focusedModelId;
    if (!id || !modelManager) {
        setStatus('⚠ 请先加载模型', false);
        return;
    }

    // 防止重复创建（UI 多次点击）
    if (modelManager.clothInstances.has(id)) {
        setStatus('⚠ 布料已存在', false);
        return;
    }

    const mmd = modelManager.focusedMmdModel();
    if (!mmd) {
        setStatus('⚠ 当前模型无 MMD 数据', false);
        return;
    }

    // Build SDF collider
    const collider = new SdfCollider();
    collider.init(DEFAULT_BODY_CAPSULES);
    _currentCollider = collider;

    // 提领模型整体高度（用于 autoFitClothDimensions 归一化）
    let modelHeight: number | undefined;

    const model = modelManager.modelRegistry.get(id);
    if (model && model.rootMesh) {
        const boundingInfo = model.rootMesh.getBoundingInfo();
        if (boundingInfo) {
            modelHeight =
                boundingInfo.boundingBox.maximumWorld.y - boundingInfo.boundingBox.minimumWorld.y;
            if (modelHeight > 0.001) {
                const defaultHeight = 2.0;
                const scaleFactor = modelHeight / defaultHeight;
                collider.scaleAll(Math.max(0.5, Math.min(2.0, scaleFactor)));
            }
        }
    }

    // Build anchor matrix function
    const anchorMatrixFn = (boneName: string): Float32Array | null => {
        return modelManager.getBoneWorldMatrix(boneName);
    };

    // Build bone parent map for dynamic capsule sizing
    const boneParentMap: Record<string, string> = {};
    const mmdForBones = modelManager.focusedMmdModel();
    if (mmdForBones) {
        for (const bone of mmdForBones.runtimeBones) {
            if (bone.parentBone) {
                boneParentMap[bone.name] = bone.parentBone.name;
            }
        }
    }

    // Dynamically size capsules based on actual bone distances
    collider.updateCapsuleSizes(anchorMatrixFn, boneParentMap);

    // Use config from envState
    const cfg = { ...envState.clothConfig };

    // 自动推算尺寸：innerRadius 仍为出厂默认值 0.12（未自定义过）或旧存档笔误值 1.0
    const atDefault =
        Math.abs(cfg.innerRadius - DEFAULT_CLOTH_CONFIG.innerRadius) < 0.001 &&
        Math.abs(cfg.length - DEFAULT_CLOTH_CONFIG.length) < 0.001;
    if (cfg.innerRadius >= 0.9 || atDefault) {
        const fitted = autoFitClothDimensions(
            cfg.anchorBone || '腰',
            anchorMatrixFn,
            mmdForBones?.runtimeBones ?? [],
            modelHeight
        );
        cfg.innerRadius = fitted.innerRadius;
        cfg.length = fitted.length;
        // 回写到 envState 以便 UI 同步
        envState.clothConfig = { ...envState.clothConfig, ...cfg };
    }

    // Create cloth
    const cloth = createCloth(scene, cfg, collider);
    // 应用全局 solver substeps
    cloth.solver.substeps = envState.solverSubsteps;
    // 应用全局重力
    cloth.solver.setGravity(0, -9.8 * _clothGravity, 0);

    // Build update function (with time scale getter)
    const updateFn = buildClothUpdateFn(
        cloth,
        anchorMatrixFn,
        collider,
        () => envState.solverTimeScale
    );

    // Register with model manager
    modelManager.addCloth(id, cloth, updateFn);

    // 应用当前碰撞状态到新布料
    _applyCollisionState();

    // 设置调试更新回调（如果调试可视化已启用）
    if (
        envState.clothDebugParticles ||
        envState.clothDebugConstraints ||
        envState.clothDebugColliders
    ) {
        setDebugUpdateFn((solver, coll) => updateDebugVisualization(solver, coll));
    }

    setStatus(
        `✓ 布料已创建 (${cloth.solver.particles.length} 粒子, ${cloth.solver.constraints.length} 约束, mesh: ${cloth.mesh ? 'ok' : 'null'})`,
        true
    );
}

/** 销毁当前聚焦模型的布料 */
function _destroyClothForFocusedModel(): void {
    const id = focusedModelId;
    if (!id || !modelManager) {
        return;
    }
    modelManager.removeCloth(id);
}

// ======== 公开 API ========

/** 切换布料模拟开关 */
export function toggleCloth(enabled: boolean): void {
    if (enabled) {
        _createClothForFocusedModel();
    } else {
        _destroyClothForFocusedModel();
    }
    envState.clothEnabled = enabled;
    _reportClothStatus();
}

/** 用当前配置重建布料（参数变更后调用）
 * @returns true 表示重建成功，false 表示布料未启用
 */
export function recreateCloth(): boolean {
    if (!envState.clothEnabled) {
        return false;
    }
    _destroyClothForFocusedModel();
    _createClothForFocusedModel();
    return true;
}

// ======== 自动推算布料尺寸 ========

/**
 * 从模型骨骼实际位置推算布料尺寸参数。
 *
 * 算法思路（v2 — 基于模型整体比例，非链段长度）：
 * - 用模型 bounding box 高度建立"身高参考"
 * - innerRadius: 用锚骨骼所在层的"截面半径"，通过在该层采样周围骨骼横向距离的中位数来估算
 * - length: BFS 找最深末端骨骼的垂直距离，按裙装比例换算（而非简单 ×0.5）
 *
 * @param anchorBoneName 锚定骨骼名（如 "腰"）
 * @param getBoneMatrix 获取骨骼世界矩阵的函数
 * @param bones MMD 运行时骨骼列表（含 parentBone 引用）
 * @param modelHeight 可选的模型高度（米），用于归一化。如果不传则从骨骼数据推估。
 * @returns 推算出的 innerRadius 和 length
 */
export function autoFitClothDimensions(
    anchorBoneName: string,
    getBoneMatrix: (name: string) => Float32Array | null,
    bones: ReadonlyArray<{
        name: string;
        parentBone: { name: string } | null;
        worldMatrix: Float32Array;
    }>,
    modelHeight?: number
): { innerRadius: number; length: number } {
    // 人体比例参考（米）：
    // 身高 1.6m → 腰节（头顶到腰）≈ 0.95m，腰围 ≈ 0.70m（半径 0.111m）
    // 身高 1.7m → 腰节 ≈ 1.01m，腰围 ≈ 0.75m（半径 0.119m）
    // 身高 1.8m → 腰节 ≈ 1.07m，腰围 ≈ 0.80m（半径 0.127m）
    const REF_HEIGHT = 1.7; // 参考身高（米）
    const REF_WAIST_RADIUS = 0.119; // 参考腰半径（米）
    const REF_WAIST_TO_FLOOR = 0.95; // 参考腰到地面（脚踝）高度（米）
    // 裙长经验值：及膝 ≈ 0.5m，及踝 ≈ 0.85m，拖地 ≈ 1.2m
    const REF_SKIRT_LENGTH = 0.65; // 参考裙长（米）

    const anchorMat = getBoneMatrix(anchorBoneName);
    if (!anchorMat) {
        return { innerRadius: REF_WAIST_RADIUS, length: REF_SKIRT_LENGTH };
    }

    const anchorBone = bones.find((b) => b.name === anchorBoneName);
    if (!anchorBone) {
        return { innerRadius: REF_WAIST_RADIUS, length: REF_SKIRT_LENGTH };
    }

    // ---- 推估模型身高（如果未传入）----
    let height = modelHeight ?? REF_HEIGHT;
    if (!modelHeight) {
        // 从骨骼 Y 范围估算：找最高和最低骨骼的 Y 差
        let minY = Infinity,
            maxY = -Infinity;
        for (const b of bones) {
            const m = getBoneMatrix(b.name);
            if (m) {
                const y = m[13]; // world matrix translation Y
                if (y < minY) {
                    minY = y;
                }
                if (y > maxY) {
                    maxY = y;
                }
            }
        }
        if (isFinite(minY) && isFinite(maxY) && maxY - minY > 0.1) {
            height = maxY - minY;
        }
    }

    // 模型身高归一化系数（把骨骼单位 → 米）
    // MMD 模型通常 1 unit ≈ 1 cm，所以直接用差值即可
    // 若模型实际身高 1.5m，height=1.5；若 2.0m，height=2.0
    const scaleFactor = height / REF_HEIGHT; // 1.0 = 标准身高，>1 = 高大，<1 = 娇小

    // ---- innerRadius：通过横向扩散采样估算 ----
    // 以锚骨骼为中心，采样同层（相近 Y 高度）所有骨骼的径向距离
    const anchorY = anchorMat[13];
    const anchorX = anchorMat[12];
    const anchorZ = anchorMat[14];

    // 收集 anchor 层附近（|Y - anchorY| < 0.1）的骨骼，统计径向距离分布
    const lateralDistances: number[] = [];
    for (const b of bones) {
        if (b.name === anchorBoneName) {
            continue;
        }
        const m = getBoneMatrix(b.name);
        if (!m) {
            continue;
        }
        const dy = Math.abs(m[13] - anchorY);
        if (dy > 0.1) {
            continue;
        } // 同层骨骼
        const dx = m[12] - anchorX;
        const dz = m[14] - anchorZ;
        const dist = Math.sqrt(dx * dx + dz * dz);
        if (dist > 0.01) {
            lateralDistances.push(dist);
        }
    }

    let innerRadius: number;
    if (lateralDistances.length >= 3) {
        // 取中位数 × 0.55 作为半径（分布通常包含左右各一半身体）
        lateralDistances.sort((a, b) => a - b);
        const medianDist = lateralDistances[Math.floor(lateralDistances.length / 2)];
        innerRadius = medianDist * 0.55;
    } else {
        // fallback：骨骼链段长度 × 系数
        const parentName = anchorBone.parentBone?.name;
        const parentMat = parentName ? getBoneMatrix(parentName) : null;
        if (parentMat) {
            const dx = anchorMat[12] - parentMat[12];
            const dy = anchorMat[13] - parentMat[13];
            const dz = anchorMat[14] - parentMat[14];
            const boneLen = Math.sqrt(dx * dx + dy * dy + dz * dz);
            innerRadius = boneLen * 0.7;
        } else {
            innerRadius = REF_WAIST_RADIUS * scaleFactor;
        }
    }

    // ---- length：从锚骨骼向下 BFS 找最深骨骼的垂直距离 ----
    let minY = anchorY;
    const visited = new Set<string>([anchorBoneName]);
    let frontier: string[] = [anchorBoneName];
    for (let depth = 0; depth < 8 && frontier.length > 0; depth++) {
        const next: string[] = [];
        for (const name of frontier) {
            for (const b of bones) {
                if (b.parentBone?.name === name && !visited.has(b.name)) {
                    visited.add(b.name);
                    next.push(b.name);
                    const m = getBoneMatrix(b.name);
                    if (m && m[13] < minY) {
                        minY = m[13];
                    }
                }
            }
        }
        frontier = next;
    }

    const verticalSpan = anchorY - minY;
    let length: number;
    if (verticalSpan > 0.1) {
        // 裙长 = max(腰到脚踝 × 60%, 参考裙长 × 身高归一化)
        // 60% 为保守余量（不过踝）；参考裙长保证极矮模型也有基础长度
        length = Math.max(verticalSpan * 0.6, REF_SKIRT_LENGTH * scaleFactor);
    } else {
        length = REF_SKIRT_LENGTH * scaleFactor;
    }

    // 宽松范围限制
    return {
        innerRadius: Math.max(0.05, Math.min(innerRadius, 0.6)),
        length: Math.max(0.15, Math.min(length, 2.2)),
    };
}

// ======== 碰撞体参数 API ========

/** 获取当前碰撞体（无布料时返回 null） */
export function getCollider(): SdfCollider | null {
    return _currentCollider;
}

/** 获取碰撞体规格列表 */
export function getColliderSpecs(): CapsuleSpec[] {
    if (!_currentCollider) {
        return [];
    }
    return _currentCollider.capsules.map((c) => ({
        name: c.name,
        boneName: c.boneName,
        radius: c.radius,
        halfHeight: c.halfHeight,
    }));
}

/** 设置单个碰撞体的半径 */
export function setCapsuleRadius(name: string, radius: number): void {
    if (!_currentCollider) {
        return;
    }
    const c = _currentCollider.capsules.find((c) => c.name === name);
    if (c) {
        c.radius = radius;
    }
}

/** 设置单个碰撞体的半高 */
export function setCapsuleHalfHeight(name: string, halfHeight: number): void {
    if (!_currentCollider) {
        return;
    }
    const c = _currentCollider.capsules.find((c) => c.name === name);
    if (c) {
        c.halfHeight = halfHeight;
    }
}

/** 设置碰撞体刚度 */
export function setColliderStiffness(stiffness: number): void {
    if (!_currentCollider) {
        return;
    }
    _currentCollider.stiffness = stiffness;
}

/** 设置碰撞体摩擦系数 */
export function setColliderFriction(friction: number): void {
    if (!_currentCollider) {
        return;
    }
    _currentCollider.friction = friction;
}

/** 开关单个碰撞体 */
export function setCapsuleEnabled(name: string, enabled: boolean): void {
    if (!_currentCollider) {
        return;
    }
    _currentCollider.setEnabledByName(name, enabled);
}

/** 全部开关碰撞体 */
export function setAllCapsulesEnabled(enabled: boolean): void {
    if (!_currentCollider) {
        return;
    }
    _currentCollider.setAllEnabled(enabled);
}

// ======== 调试可视化 API ========

/** 获取或创建调试渲染器 */
function _getRenderer(): XpbdRenderer {
    if (!_renderer && scene) {
        _renderer = new XpbdRenderer(scene);
    }
    return _renderer!;
}

/** 开关粒子可视化 */
export function setDebugParticles(enabled: boolean): void {
    envState.clothDebugParticles = enabled;
    const r = _getRenderer();
    if (r) {
        r.showParticles(enabled);
    }
    _syncDebugUpdateFn();
}

/** 开关约束可视化 */
export function setDebugConstraints(enabled: boolean): void {
    envState.clothDebugConstraints = enabled;
    const r = _getRenderer();
    if (r) {
        r.showConstraints(enabled);
    }
    _syncDebugUpdateFn();
}

/** 开关碰撞体可视化 */
export function setDebugColliders(enabled: boolean): void {
    envState.clothDebugColliders = enabled;
    const r = _getRenderer();
    if (r) {
        r.showColliders(enabled);
    }
    _syncDebugUpdateFn();
}

/** 同步调试更新回调 */
function _syncDebugUpdateFn(): void {
    if (
        envState.clothDebugParticles ||
        envState.clothDebugConstraints ||
        envState.clothDebugColliders
    ) {
        setDebugUpdateFn((solver, coll) => updateDebugVisualization(solver, coll));
    } else {
        setDebugUpdateFn(null);
    }
}

/** 获取调试状态 */
export function getDebugState(): { particles: boolean; constraints: boolean; colliders: boolean } {
    return {
        particles: envState.clothDebugParticles,
        constraints: envState.clothDebugConstraints,
        colliders: envState.clothDebugColliders,
    };
}

/** 更新调试可视化（每帧调用） */
export function updateDebugVisualization(
    solver: import('./xpbd-solver').XpbdSolver,
    collider: SdfCollider | null
): void {
    const r = _getRenderer();
    if (!r) {
        return;
    }

    if (envState.clothDebugParticles) {
        r.updateParticles(solver);
    }
    if (envState.clothDebugConstraints) {
        r.updateConstraints(solver);
    }
    if (envState.clothDebugColliders && collider) {
        r.updateColliders(collider);
    }
}

/** 销毁调试渲染器 */
export function disposeDebugRenderer(): void {
    if (_renderer) {
        _renderer.dispose();
        _renderer = null;
    }
    envState.clothDebugParticles = false;
    envState.clothDebugConstraints = false;
    envState.clothDebugColliders = false;
}

// ======== 碰撞状态同步（内部）========

/** 应用当前 envState 碰撞开关到所有布料和碰撞体 */
function _applyCollisionState(): void {
    const groundEffective = envState.collisionEnabled && envState.groundCollisionEnabled;
    const bodyEffective = envState.collisionEnabled && envState.bodyCollisionEnabled;

    for (const [, cloth] of modelManager.clothInstances) {
        if (cloth && cloth.solver) {
            cloth.solver.groundCollisionEnabled = groundEffective;
        }
    }

    if (_currentCollider) {
        _currentCollider.setAllEnabled(bodyEffective);
    }
}

