        inst.mmdModel.setRuntimeAnimation(null);
    }
    modelManager?.clearVmdData(id);
    if (isPlaying) {
        mmdRuntime.pauseAnimation();
        setIsPlaying(false);
    }
    updatePlaybackUI();
